import React, { useEffect, useState, useCallback } from 'react';

/**
 * VoiceCommandHandler provides continuous listening mode using the Web Speech API.
 * It is a non-UI component that emits spoken transcripts to an 'onCommand' callback.
 */
export default function VoiceCommandHandler({ onCommand, isListening, language = 'en-US' }) {
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!isListening) return;

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('Web Speech API is not supported in this browser.');
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = false;
    recognition.lang = language;

    recognition.onresult = (event) => {
      const last = event.results.length - 1;
      const transcript = event.results[last][0].transcript.trim();
      if (transcript && onCommand) {
        onCommand(transcript);
      }
    };

    recognition.onerror = (event) => {
      console.error('[VoiceCommandHandler] Error:', event.error);
      setError(`Speech error: ${event.error}`);
    };

    try {
      recognition.start();
    } catch (e) {
      console.error('[VoiceCommandHandler] Failed to start recognition', e);
    }

    return () => {
      try {
        recognition.stop();
      } catch (e) {
        // ignore
      }
    };
  }, [isListening, onCommand, language]);

  if (error) {
    return <div style={{ display: 'none' }} data-testid="voice-error">{error}</div>;
  }

  return <div style={{ display: 'none' }} data-testid="voice-listening-status">{isListening ? 'listening' : 'idle'}</div>;
}

import { StrictMode, Suspense, lazy } from 'react'
import { createRoot } from 'react-dom/client'
import './index.css'
import { ErrorBoundary } from './components/ErrorBoundary.jsx'
import './superbrain/lib/troikaConfig' // main-thread text (no blob worker / eval) — CSP hardening; must precede any <Text>
import './superbrain/lib/monacoConfig'

// GAGOS — THE VOYAGING MIND is the one and only frontend (operator's decision,
// 2026-06-21): the points-being lives at the clean root URL. No ?ui flags, no
// classic IDE, no manufacturing shell — one mind, one URL.
//
// The superbrain tree is PORT-MANAGED (overwritten byte-for-byte by `npm run
// port`), so the error boundary that protects it is mounted HERE in this
// product-authored file — a DOM parent of the lazy shell, outside its Suspense
// subtree — catching a render fault anywhere in the superbrain subtree without
// editing any generated file.
const SuperbrainApp = lazy(() => import('./superbrain/SuperbrainApp.jsx'))

createRoot(document.getElementById('root')).render(
  <StrictMode>
    <ErrorBoundary name="App">
      <Suspense fallback={null}>
        <SuperbrainApp />
      </Suspense>
    </ErrorBoundary>
  </StrictMode>,
)

/**
 * The superbrain experience — the single official frontend at the clean root /.
 *
 * CHROME (2026-06-20): the home was PURE 3D, but raw in-world 3D text read as
 * floating debug labels (operator: "not professional"). The being stays the
 * diegetic 3D hero on the canvas; identity / live status / the conversation now
 * live in <GagosChrome/>, a crisp 2D product layer DOM-sibling to the canvas.
 * GagosChrome drives turns through the same adapter and cognition bus the being
 * already listens to, so the organism still arrives, listens and reacts.
 */
import { lazy, Suspense, useCallback, useState } from 'react';
import BootSequence from '@/components/ui/BootSequence';
import GagosChrome from '../workbench/GagosChrome';
import SuperbrainReactiveEffects from '../workbench/SuperbrainReactiveEffects';
import FileTree from '../workbench/FileTree';
import TerminalPanel from '../workbench/TerminalPanel';
import CodeEditor from '../workbench/CodeEditor';
import BudgetMicroBar from '../workbench/BudgetMicroBar';
import CouncilDeliberationPanel from '../workbench/CouncilDeliberationPanel';
import EcosystemDashboard from '../workbench/EcosystemDashboard';
import MemoryBrowser from '../workbench/MemoryBrowser';
import SettingsPanel from '../workbench/SettingsPanel';
import StigmergyPanel from '../workbench/StigmergyPanel';
import VultureFeed from '../workbench/VultureFeed';
import VoiceCommandHandler from '../components/VoiceCommandHandler';
import MobileHUD from '../components/MobileHUD';
import './superbrain.css';

const WorkspaceCanvas = lazy(() => import('@/components/canvas/WorkspaceCanvas'));

export default function SuperbrainApp() {
  const [booted, setBooted] = useState(false);
  const [activeFile, setActiveFile] = useState(null);
  const [fileTreeOpen, setFileTreeOpen] = useState(true);
  const [councilOpen, setCouncilOpen] = useState(true);
  const [memoryOpen, setMemoryOpen] = useState(true);
  const [stigmergyOpen, setStigmergyOpen] = useState(true);
  const [vultureOpen, setVultureOpen] = useState(true);
  const [ecosystemOpen, setEcosystemOpen] = useState(true);
  const [settingsOpen, setSettingsOpen] = useState(true);
  const [isListening, setIsListening] = useState(false);

  const handleBootComplete = useCallback(() => setBooted(true), []);

  const handleVoiceCommand = useCallback((transcript) => {
    console.log('[Voice Command Received]', transcript);
    // Ideally this would dispatch to the cognition bus or intent router
  }, []);

  return (
    <div className="font-sans antialiased" style={{ position: 'relative', width: '100vw', height: '100vh', overflow: 'hidden' }}>
      <BootSequence onComplete={handleBootComplete} />

      {/* Z-index: 0 */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
        <Suspense fallback={null}>
          <WorkspaceCanvas booted={booted}>
            <SuperbrainReactiveEffects />
          </WorkspaceCanvas>
        </Suspense>
      </div>

      {/* Z-index: 10 */}
      <main aria-label="GAGOS" style={{ position: 'absolute', inset: 0, zIndex: 10, pointerEvents: 'none' }}>
        <GagosChrome />
      </main>

      {/* Z-index: 15 (TerminalPanel handles its own fixed positioning) */}
      <div style={{ zIndex: 15, position: 'relative' }}>
        <TerminalPanel />
      </div>

      {/* Z-index: 20 */}
      <MobileHUD>
        <div style={{ position: 'absolute', inset: 0, zIndex: 20, pointerEvents: 'none' }}>
          <BudgetMicroBar />
          {fileTreeOpen && (
            <FileTree 
              onClose={() => setFileTreeOpen(false)} 
              onOpenFile={(file) => setActiveFile(file)} 
            />
          )}
          {activeFile && (
            <CodeEditor 
              file={activeFile} 
              onClose={() => setActiveFile(null)} 
            />
          )}
          {councilOpen && (
            <CouncilDeliberationPanel onClose={() => setCouncilOpen(false)} />
          )}
          {memoryOpen && (
            <MemoryBrowser onClose={() => setMemoryOpen(false)} />
          )}
          {stigmergyOpen && (
            <StigmergyPanel onClose={() => setStigmergyOpen(false)} />
          )}
          {vultureOpen && (
            <VultureFeed onClose={() => setVultureOpen(false)} />
          )}
          {ecosystemOpen && (
            <EcosystemDashboard onClose={() => setEcosystemOpen(false)} />
          )}
          {settingsOpen && (
            <SettingsPanel onClose={() => setSettingsOpen(false)} />
          )}
        </div>
      </MobileHUD>

      <VoiceCommandHandler 
        isListening={isListening} 
        onCommand={handleVoiceCommand} 
      />
    </div>
  );
}

'use client';

/**
 * QualityTierProvider — the organism's metabolic governor.
 *
 * The effective tier every consumer obeys is composed from two signals:
 *
 *   baseTier   what this machine has PROVEN it can sustain. Starts from the
 *              persisted verdict in localStorage (default 'high'), and is
 *              demoted — never auto-promoted — by the in-canvas TierGovernor
 *              when measured frame rate declines. A demotion is evidence; it
 *              sticks across sessions until the operator overrides it.
 *
 *   generating GAGOS is mid-turn (between a 'directive' and the next
 *              'synthesis'/'approval-required' on the cognition bus). While
 *              the local model is thinking it owns the machine's memory
 *              bandwidth, so the interface dims its own cortex by one tier
 *              for the duration — the product-aware degrade no generic demo
 *              can have.
 */

import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { subscribeCognition } from '@/lib/cognitionBus';

export type QualityTier = 'low' | 'medium' | 'high';

/** v3: FIDELITY IS SACRED (the operator's law — see VISION.md). Only the
 *  operator's own click is ever stored here; the governor lost its write
 *  access entirely (it advises in the terminal, never acts). All earlier
 *  keys held machine-written verdicts — removed on load. */
const STORAGE_KEY = 'gag-quality-tier-v3';
const LEGACY_STORAGE_KEYS = ['gag-quality-tier', 'gag-quality-tier-v2'];
const TIERS: readonly QualityTier[] = ['low', 'medium', 'high'];

export function isQualityTier(value: unknown): value is QualityTier {
  return typeof value === 'string' && (TIERS as readonly string[]).includes(value);
}

/** One step down; 'low' is the floor. */
export function demoteTier(tier: QualityTier): QualityTier {
  return tier === 'high' ? 'medium' : 'low';
}

/** The tier consumers obey: the proven base, dimmed while the model thinks. */
export function effectiveTier(base: QualityTier, generating: boolean): QualityTier {
  return generating ? demoteTier(base) : base;
}

function readStoredTier(): QualityTier | null {
  if (typeof window === 'undefined') return null;
  try {
    for (const legacy of LEGACY_STORAGE_KEYS) {
      window.localStorage.removeItem(legacy);
    }
    const stored = window.localStorage.getItem(STORAGE_KEY);
    return isQualityTier(stored) ? stored : null;
  } catch {
    return null;
  }
}

interface QualityTierContextValue {
  /** STRUCTURAL tier: governs geometry — shells, web octaves, particle
   *  counts, the sky. Changes only with the machine's proven capability,
   *  never mid-conversation: the look must not be amputated while the
   *  operator watches. */
  tier: QualityTier;
  /** PERF tier: governs continuous costs (dpr, post-FX extras). Drops one
   *  step while the model is generating — resolution breathes, geometry
   *  stays. */
  perfTier: QualityTier;
  /** The machine's proven capability (persisted; demote-only ratchet). */
  baseTier: QualityTier;
  /** True while a real GAGOS turn is streaming. */
  generating: boolean;
  /** Operator/governor override of the base tier; persisted. */
  setTier: (tier: QualityTier) => void;
}

const QualityTierContext = createContext<QualityTierContextValue>({
  tier: 'high',
  perfTier: 'high',
  baseTier: 'high',
  generating: false,
  setTier: () => {},
});

export function useQualityTier() {
  return useContext(QualityTierContext);
}

export function QualityTierProvider({
  children,
  defaultTier = 'high',
}: {
  children: React.ReactNode;
  defaultTier?: QualityTier;
}) {
  const [baseTier, setBaseTier] = useState<QualityTier>(
    () => readStoredTier() ?? defaultTier,
  );
  const [generating, setGenerating] = useState(false);

  const setTier = useCallback((tier: QualityTier) => {
    if (!isQualityTier(tier)) return;
    setBaseTier(tier);
    try {
      window.localStorage.setItem(STORAGE_KEY, tier);
    } catch {
      // Private mode etc. — the session still gets the right tier.
    }
  }, []);

  // The product signal: dim while GAGOS is mid-turn. 'directive' opens a
  // turn; ANY settling event — a synthesis (including the adapter's honest
  // LINK OFFLINE) or an approval hold — closes it.
  useEffect(() => {
    return subscribeCognition((event) => {
      if (event.type === 'directive') setGenerating(true);
      else if (event.type === 'synthesis' || event.type === 'approval-required') {
        setGenerating(false);
      }
    });
  }, []);

  const value = useMemo(
    () => ({
      // FIDELITY IS SACRED: the operator's chosen tier is THE tier — for
      // structure AND continuous costs alike. Nothing automatic dims it;
      // `generating` is pure status (the HUD shows '· thinking').
      tier: baseTier,
      perfTier: baseTier,
      baseTier,
      generating,
      setTier,
    }),
    [baseTier, generating, setTier],
  );

  return (
    <QualityTierContext.Provider value={value}>
      {children}
    </QualityTierContext.Provider>
  );
}

import { useFrame } from '@react-three/fiber';
import { BODY_POSTURES, postureColor01, POSTURE_DIAL, type BodyPosture } from '@/lib/bodyPosture';
import { useEffect, useMemo, useRef } from 'react';
import * as THREE from 'three';
import type { AnatomicalConductorSnapshot, AnatomicalVertebraSignal } from '@/lib/anatomicalConductor';
import type { AnatomicalRootSystemSnapshot, AnatomicalRootStrand, CaudaEquinaTrace } from '@/lib/anatomicalRootSystem';

const BEAD_COUNT = 3;
const ROOT_FAN_PUNCTA = 4;
const CAUDA_TRACE_PUNCTA = 3;

type RenderRootFan = {
  key: string;
  role: AnatomicalRootStrand['role'];
  flow: AnatomicalRootStrand['flow'];
  opacity: number;
  tension: number;
  beadSpeed: number;
  pulseRate: number;
  tint: string;
  secondaryTint: string;
  memoryTrace: number;
  flowDelay: number;
  side: AnatomicalRootStrand['side'];
  channel: AnatomicalRootStrand['channel'];
  curve: THREE.CatmullRomCurve3;
  geometry: THREE.TubeGeometry;
};

function clamp01(value: number): number {
  return THREE.MathUtils.clamp(value, 0, 1);
}

function signalPosition(signal: AnatomicalVertebraSignal): THREE.Vector3 {
  const [x, y, z] = signal.anchorLocal;
  return new THREE.Vector3(x, y, z + 0.09);
}

function tuplePosition(tuple: [number, number, number]): THREE.Vector3 {
  return new THREE.Vector3(tuple[0], tuple[1], tuple[2] + 0.09);
}

function rootRoleGain(role: AnatomicalRootStrand['role']): number {
  if (role === 'holding') return 1.28;
  if (role === 'error') return 1.34;
  if (role === 'conducting') return 1.18;
  if (role === 'gripping') return 1.08;
  if (role === 'reabsorbing') return 1.02;
  if (role === 'sensing') return 0.66;
  return 0;
}

function rootWaveRate(root: Pick<AnatomicalRootStrand, 'role' | 'flow' | 'pulseRate'>): number {
  if (root.role === 'holding') return 1.1;
  if (root.role === 'error') return 5.2;
  if (root.role === 'reabsorbing') return 1.8;
  if (root.flow === 'return') return 2.3;
  return Math.max(1.2, root.pulseRate);
}

function rootTravelDirection(flow: AnatomicalRootStrand['flow'] | CaudaEquinaTrace['flow']): number {
  return flow === 'return' ? -1 : 1;
}

export default function AnatomicalConductorOverlay({
  anatomy,
  rootSystem,
  reducedMotion,
  bodyPosture = BODY_POSTURES.rest,
}: {
  anatomy: AnatomicalConductorSnapshot;
  rootSystem?: AnatomicalRootSystemSnapshot;
  reducedMotion: boolean;
  bodyPosture?: BodyPosture;
}) {
  const socketRefs = useRef<THREE.Mesh[]>([]);
  const nodeRefs = useRef<THREE.Mesh[]>([]);
  const lateralRefs = useRef<THREE.Mesh[]>([]);
  const fanRefs = useRef<THREE.Mesh[]>([]);
  const fanPunctaRefs = useRef<THREE.Mesh[]>([]);
  const caudaRefs = useRef<THREE.Mesh[]>([]);
  const caudaPunctaRefs = useRef<THREE.Mesh[]>([]);
  const trunkRef = useRef<THREE.Mesh>(null);
  const beadRefs = useRef<THREE.Mesh[]>([]);
  // Posture wash: the conductor trunk/beads/cauda/puncta settle into the body's
  // current hue (spectral-v1), blended OVER the anatomy tint. Role-colored signals
  // and fans (amber hold / red error) keep their semantic colors on top.
  const trunkColor = useMemo(() => {
    const [pr, pg, pb] = postureColor01(bodyPosture.color);
    return new THREE.Color(anatomy.trunkTint).lerp(
      new THREE.Color(pr, pg, pb),
      Math.min(0.8, bodyPosture.tint * POSTURE_DIAL.surfaceScale),
    );
  }, [anatomy.trunkTint, bodyPosture.color, bodyPosture.tint]);

  const activeSignals = anatomy.vertebrae.filter((signal) => signal.role !== 'idle');

  const trunkCurve = useMemo(() => {
    const points = anatomy.conductingSeatIndexes
      .map((seatIndex) => anatomy.vertebrae[seatIndex])
      .filter(Boolean)
      .map(signalPosition);
    if (points.length < 2) return null;
    return new THREE.CatmullRomCurve3(points);
  }, [anatomy.conductingSeatIndexes, anatomy.vertebrae]);

  const trunkGeometry = useMemo(() => {
    if (!trunkCurve) return null;
    return new THREE.TubeGeometry(trunkCurve, 42, 0.0055, 7, false);
  }, [trunkCurve]);

  const fallbackRootFans = useMemo<RenderRootFan[]>(() => {
    return activeSignals.flatMap((signal) => {
      const anchor = signalPosition(signal);
      const seatFactor = signal.seatIndex / Math.max(1, anatomy.vertebrae.length - 1);
      const length = 0.22 + seatFactor * 0.34 + signal.intensity * 0.08;
      const droop = 0.08 + seatFactor * 0.16;
      return [-1, 1].flatMap((side) =>
        [-1, 1].map((channel) => {
          const channelOffset = channel * (0.018 + seatFactor * 0.01);
          const start = anchor.clone().add(new THREE.Vector3(side * 0.025, channelOffset, 0.006));
          const midA = anchor
            .clone()
            .add(new THREE.Vector3(side * (length * 0.26), channelOffset - droop * 0.18, 0.042));
          const midB = anchor
            .clone()
            .add(new THREE.Vector3(side * (length * 0.64), channelOffset - droop * 0.55, 0.035));
          const end = anchor
            .clone()
            .add(new THREE.Vector3(side * length, channelOffset - droop * (0.86 + channel * 0.16), 0.018));
          const curve = new THREE.CatmullRomCurve3([start, midA, midB, end]);
          const role: AnatomicalRootStrand['role'] =
            signal.role === 'held'
              ? 'holding'
              : signal.role === 'active'
                ? 'conducting'
                : signal.role === 'reabsorbing'
                  ? 'reabsorbing'
                  : 'sensing';
          return {
            key: `${signal.seatIndex}-${side}-${channel}`,
            role,
            flow: role === 'reabsorbing' ? 'return' : role === 'conducting' ? 'outbound' : 'bidirectional',
            opacity: signal.rootOpacity,
            tension: signal.intensity,
            beadSpeed: signal.role === 'held' ? 0.07 : signal.role === 'waiting' ? 0.08 : 0.2,
            pulseRate: signal.role === 'held' ? 1.1 : 2.6,
            tint: signal.tint,
            secondaryTint: anatomy.trunkTint,
            memoryTrace: signal.role === 'reabsorbing' ? 0.7 : 0,
            flowDelay: signal.flowDelay,
            side: side > 0 ? 'right' : 'left',
            channel: channel > 0 ? 'upper' : 'lower',
            curve,
            geometry: new THREE.TubeGeometry(curve, 24, 0.0036 + signal.intensity * 0.0028, 6, false),
          };
        }),
      );
    });
  }, [activeSignals, anatomy.vertebrae.length]);

  const rootFans = useMemo<RenderRootFan[]>(() => {
    if (!rootSystem) return fallbackRootFans;
    return rootSystem.strands.map((strand) => {
      const curve = new THREE.CatmullRomCurve3([
        tuplePosition(strand.startLocal),
        tuplePosition(strand.midALocal),
        tuplePosition(strand.midBLocal),
        tuplePosition(strand.endLocal),
      ]);
      return {
        key: strand.id,
        role: strand.role,
        flow: strand.flow,
        opacity: strand.opacity,
        tension: strand.tension,
        beadSpeed: strand.beadSpeed,
        pulseRate: strand.pulseRate,
        tint: strand.tint,
        secondaryTint: strand.secondaryTint,
        memoryTrace: strand.memoryTrace,
        flowDelay: strand.flowDelay,
        side: strand.side,
        channel: strand.channel,
        curve,
        geometry: new THREE.TubeGeometry(curve, 28, strand.radius, 7, false),
      };
    });
  }, [fallbackRootFans, rootSystem]);

  const caudaTraces = useMemo(() => {
    return (rootSystem?.caudaTraces ?? []).map((trace) => {
      const curve = new THREE.CatmullRomCurve3([
        tuplePosition(trace.startLocal),
        tuplePosition(trace.midLocal),
        tuplePosition(trace.endLocal),
      ]);
      return {
        ...trace,
        curve,
        geometry: new THREE.TubeGeometry(curve, 32, trace.radius, 7, false),
      };
    });
  }, [rootSystem]);

  useEffect(() => {
    return () => {
      trunkGeometry?.dispose();
      rootFans.forEach((fan) => fan.geometry.dispose());
      caudaTraces.forEach((trace) => trace.geometry.dispose());
    };
  }, [caudaTraces, rootFans, trunkGeometry]);

  useFrame((state) => {
    const time = state.clock.elapsedTime;
    const globalWave = reducedMotion ? 0.82 : 0.72 + 0.28 * (0.5 + 0.5 * Math.sin(time * 2.7));

    for (const signal of activeSignals) {
      const socket = socketRefs.current[signal.seatIndex];
      const node = nodeRefs.current[signal.seatIndex];
      const color = new THREE.Color(signal.tint);
      const wave =
        reducedMotion || signal.role === 'waiting'
          ? 0.86
          : 0.76 + 0.24 * (0.5 + 0.5 * Math.sin(time * (signal.role === 'held' ? 1.35 : 3.2) + signal.flowDelay * 18));
      const socketOpacity = clamp01(signal.socketOpacity * wave);
      const rootOpacity = clamp01(signal.rootOpacity * (0.72 + globalWave * 0.28));

      if (socket) {
        socket.scale.setScalar(signal.ringScale * (0.92 + signal.intensity * 0.18 * wave));
        const mat = socket.material as THREE.MeshBasicMaterial;
        mat.color.copy(color);
        mat.opacity = socketOpacity;
      }

      if (node) {
        node.scale.setScalar(0.62 + signal.intensity * 0.42);
        const mat = node.material as THREE.MeshBasicMaterial;
        mat.color.copy(color);
        mat.opacity = rootOpacity;
      }

      const left = lateralRefs.current[signal.seatIndex * 2];
      const right = lateralRefs.current[signal.seatIndex * 2 + 1];
      for (const lateral of [left, right]) {
        if (!lateral) continue;
        lateral.scale.setScalar(0.46 + signal.intensity * 0.32);
        const mat = lateral.material as THREE.MeshBasicMaterial;
        mat.color.copy(color);
        mat.opacity = Math.min(0.3, rootOpacity * 0.92);
      }
    }

    rootFans.forEach((fan, index) => {
      const root = fanRefs.current[index];
      if (!root) return;
      const color = new THREE.Color(fan.tint);
      const roleGain = rootRoleGain(fan.role);
      const wave =
        reducedMotion || fan.role === 'sensing'
          ? 0.8
          : 0.66 + 0.34 * (0.5 + 0.5 * Math.sin(time * rootWaveRate(fan) + fan.flowDelay * 16));
      const mat = root.material as THREE.MeshBasicMaterial;
      mat.color.copy(color);
      mat.opacity = Math.min(0.34, fan.opacity * roleGain * wave);
    });

    caudaTraces.forEach((trace, index) => {
      const root = caudaRefs.current[index];
      if (!root) return;
      const color = new THREE.Color(trace.tint);
      const wave = reducedMotion ? 0.78 : 0.68 + 0.32 * (0.5 + 0.5 * Math.sin(time * 1.7 + trace.flowDelay * 13));
      const mat = root.material as THREE.MeshBasicMaterial;
      mat.color.copy(color).lerp(trunkColor, 0.14);
      mat.opacity = Math.min(0.32, trace.opacity * (0.7 + trace.memoryStrength * 0.48) * wave);
    });

    if (trunkRef.current && trunkGeometry) {
      const geometry = trunkRef.current.geometry;
      const drawCount = geometry.getIndex()?.count ?? geometry.getAttribute('position').count;
      geometry.setDrawRange(0, Math.max(2, Math.floor(drawCount * Math.max(0.08, anatomy.trunkIntensity))));
      const mat = trunkRef.current.material as THREE.MeshBasicMaterial;
      mat.color.copy(trunkColor);
      mat.opacity = Math.min(0.18, anatomy.trunkIntensity * globalWave * 0.18);
    }

    if (!trunkCurve) return;
    beadRefs.current.forEach((bead, index) => {
      if (!bead) return;
      const travel = reducedMotion ? 0.92 : (time * 0.24 + index * 0.31) % 1;
      bead.position.copy(trunkCurve.getPointAt(clamp01(travel)));
      bead.scale.setScalar(0.32 + anatomy.trunkIntensity * 0.42);
      const mat = bead.material as THREE.MeshBasicMaterial;
      mat.color.copy(trunkColor);
      mat.opacity = Math.min(0.54, anatomy.trunkIntensity * (0.45 + globalWave * 0.35));
    });

    rootFans.forEach((fan, fanIndex) => {
      const color = new THREE.Color(fan.tint);
      for (let punctaIndex = 0; punctaIndex < ROOT_FAN_PUNCTA; punctaIndex += 1) {
        const punctum = fanPunctaRefs.current[fanIndex * ROOT_FAN_PUNCTA + punctaIndex];
        if (!punctum) continue;
        const base = (punctaIndex + 1) / (ROOT_FAN_PUNCTA + 1);
        const travel =
          reducedMotion || fan.role === 'holding'
            ? base
            : (base + time * rootTravelDirection(fan.flow) * Math.max(0.02, fan.beadSpeed * 0.12) + fan.flowDelay) % 1;
        punctum.position.copy(fan.curve.getPointAt(clamp01(travel < 0 ? travel + 1 : travel)));
        const roleGain = fan.role === 'sensing' ? 0.48 : fan.role === 'holding' ? 1.12 : fan.role === 'error' ? 1.22 : 0.92;
        punctum.scale.setScalar((0.34 + fan.tension * 0.3 + fan.memoryTrace * 0.18) * (0.82 + globalWave * 0.2));
        const mat = punctum.material as THREE.MeshBasicMaterial;
        mat.color.copy(color).lerp(trunkColor, 0.18).lerp(new THREE.Color(fan.secondaryTint), 0.18);
        mat.opacity = Math.min(0.56, fan.opacity * roleGain * (0.68 + globalWave * 0.28));
      }
    });

    caudaTraces.forEach((trace, traceIndex) => {
      const color = new THREE.Color(trace.tint);
      for (let punctaIndex = 0; punctaIndex < CAUDA_TRACE_PUNCTA; punctaIndex += 1) {
        const punctum = caudaPunctaRefs.current[traceIndex * CAUDA_TRACE_PUNCTA + punctaIndex];
        if (!punctum) continue;
        const base = (punctaIndex + 1) / (CAUDA_TRACE_PUNCTA + 1);
        const travel = reducedMotion
          ? base
          : (base - time * Math.max(0.018, trace.beadSpeed * 0.09) + trace.flowDelay) % 1;
        punctum.position.copy(trace.curve.getPointAt(clamp01(travel < 0 ? travel + 1 : travel)));
        punctum.scale.setScalar((0.4 + trace.memoryStrength * 0.35) * (0.82 + globalWave * 0.24));
        const mat = punctum.material as THREE.MeshBasicMaterial;
        mat.color.copy(color).lerp(trunkColor, 0.2);
        mat.opacity = Math.min(0.58, trace.opacity * (0.76 + trace.memoryStrength * 0.48) * (0.66 + globalWave * 0.3));
      }
    });
  });

  if (activeSignals.length === 0) return null;

  return (
    <group renderOrder={11}>
      {trunkGeometry ? (
        <mesh ref={trunkRef} geometry={trunkGeometry} frustumCulled={false} renderOrder={10}>
          <meshBasicMaterial
            color={trunkColor}
            transparent
            opacity={0}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
          />
        </mesh>
      ) : null}
      {trunkCurve
        ? Array.from({ length: BEAD_COUNT }, (_, index) => (
            <mesh
              key={`anatomical-conductor-bead-${index}`}
              ref={(mesh) => {
                if (mesh) beadRefs.current[index] = mesh;
              }}
              renderOrder={12}
            >
              <sphereGeometry args={[0.017, 12, 10]} />
              <meshBasicMaterial
                color={trunkColor}
                transparent
                opacity={0}
                blending={THREE.AdditiveBlending}
                depthWrite={false}
              />
            </mesh>
          ))
        : null}
      {rootFans.map((fan, index) => (
        <mesh
          key={`anatomical-root-fan-${fan.key}`}
          ref={(mesh) => {
            if (mesh) fanRefs.current[index] = mesh;
          }}
          geometry={fan.geometry}
          frustumCulled={false}
          renderOrder={11}
        >
          <meshBasicMaterial
            color={fan.tint}
            transparent
            opacity={0}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
          />
        </mesh>
      ))}
      {caudaTraces.map((trace, index) => (
        <mesh
          key={`cauda-memory-trace-${trace.id}`}
          ref={(mesh) => {
            if (mesh) caudaRefs.current[index] = mesh;
          }}
          geometry={trace.geometry}
          frustumCulled={false}
          renderOrder={10}
        >
          <meshBasicMaterial
            color={trace.tint}
            transparent
            opacity={0}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
          />
        </mesh>
      ))}
      {rootFans.flatMap((fan, fanIndex) =>
        Array.from({ length: ROOT_FAN_PUNCTA }, (_, punctaIndex) => {
          const index = fanIndex * ROOT_FAN_PUNCTA + punctaIndex;
          return (
            <mesh
              key={`anatomical-root-puncta-${fan.key}-${punctaIndex}`}
              ref={(mesh) => {
                if (mesh) fanPunctaRefs.current[index] = mesh;
              }}
              renderOrder={12}
            >
              <sphereGeometry args={[0.0105, 9, 7]} />
              <meshBasicMaterial
                color={fan.tint}
                transparent
                opacity={0}
                blending={THREE.AdditiveBlending}
                depthWrite={false}
              />
            </mesh>
          );
        }),
      )}
      {caudaTraces.flatMap((trace, traceIndex) =>
        Array.from({ length: CAUDA_TRACE_PUNCTA }, (_, punctaIndex) => {
          const index = traceIndex * CAUDA_TRACE_PUNCTA + punctaIndex;
          return (
            <mesh
              key={`cauda-trace-puncta-${trace.id}-${punctaIndex}`}
              ref={(mesh) => {
                if (mesh) caudaPunctaRefs.current[index] = mesh;
              }}
              renderOrder={12}
            >
              <sphereGeometry args={[0.0115, 9, 7]} />
              <meshBasicMaterial
                color={trace.tint}
                transparent
                opacity={0}
                blending={THREE.AdditiveBlending}
                depthWrite={false}
              />
            </mesh>
          );
        }),
      )}
      {activeSignals.map((signal) => (
        <group key={`anatomical-vertebra-${signal.seatIndex}`} position={signal.anchorLocal}>
          <mesh
            ref={(mesh) => {
              if (mesh) socketRefs.current[signal.seatIndex] = mesh;
            }}
            position={[0, 0, 0.086]}
            renderOrder={12}
          >
            <torusGeometry args={[0.088, 0.0042, 7, 36]} />
            <meshBasicMaterial
              color={signal.tint}
              transparent
              opacity={0}
              blending={THREE.AdditiveBlending}
              depthWrite={false}
              side={THREE.DoubleSide}
            />
          </mesh>
          <mesh
            ref={(mesh) => {
              if (mesh) nodeRefs.current[signal.seatIndex] = mesh;
            }}
            position={[0, 0, 0.108]}
            renderOrder={13}
          >
            <sphereGeometry args={[0.018, 12, 10]} />
            <meshBasicMaterial
              color={signal.tint}
              transparent
              opacity={0}
              blending={THREE.AdditiveBlending}
              depthWrite={false}
            />
          </mesh>
          {[-1, 1].map((side, sideIndex) => (
            <mesh
              key={`anatomical-vertebra-lateral-${signal.seatIndex}-${side}`}
              ref={(mesh) => {
                if (mesh) lateralRefs.current[signal.seatIndex * 2 + sideIndex] = mesh;
              }}
              position={[side * 0.112, 0, 0.1]}
              renderOrder={13}
            >
              <sphereGeometry args={[0.012, 10, 8]} />
              <meshBasicMaterial
                color={signal.tint}
                transparent
                opacity={0}
                blending={THREE.AdditiveBlending}
                depthWrite={false}
              />
            </mesh>
          ))}
        </group>
      ))}
    </group>
  );
}

'use client';

import { useEffect, useMemo, useRef, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { publishCognition } from '@/lib/cognitionBus';
import { getKnownTrails, trailLabel, type TrailRow } from '@/lib/aiosAdapter';

type Point = readonly [number, number, number];

const SLOT_SECONDS = 6;
const VARIANT_COUNT = 3;
const ROUTE_POINT_COUNT = 54;
/**
 * Phase at which the returning retrieval packet reaches the brain (path
 * progress hits 0 at the origin — see the `1 - smoothstep(0.56, 0.82, phase)`
 * return interpolation). Crossing this edge is the ABSORB moment: the cortex
 * has eaten the knowledge, so the whole OS is notified exactly once.
 */
const ABSORB_PHASE = 0.82;
/** Publish window upper bound: avoids a spurious mount-time publish when a
 *  component first evaluates deep into an already-absorbed cycle. */
const ABSORB_PHASE_MAX = 0.92;
/** The receive flare brightens ~20% for this long after absorption. */
const ABSORB_PULSE_SECONDS = 0.5;

/**
 * The glints are no longer lore: each cycle recalls a REAL trail from the
 * GAGOS pheromone map (the trail for a given absolute slot is a pure function
 * of the slot, so every sub-component agrees without shared state). The
 * absorb moment publishes a RECALL — a label-anchored cortical burst that
 * lights the matching anatomical region — never 'knowledge-acquired', which
 * is reserved for genuine trail reinforcement reported by the adapter.
 */
export function trailForSlot(slot: number): TrailRow | null {
  const trails = getKnownTrails();
  if (trails.length === 0) return null;
  return trails[slot % trails.length];
}

/** Quarantined trails wear the stain: a desaturated warning red. */
const QUARANTINE_CAGE = new THREE.Color('#c2483f');
/**
 * Scale applied to the wire cage and its receive offset so the whole target
 * reads as a small distant glint rather than a brain-scale structure.
 */
const CAGE_SCALE = 0.5;
/*
 * Core crystals are intentionally pale gold-white and ADDITIVE: a solid lit
 * near-black octahedron here previously rendered as an opaque faceted mass
 * (and, while depth-writing at opacity 0, punched black holes through the
 * additive nebula/aura layers behind it). Additive pale glow can never read
 * as a black blob, whatever the animation phase.
 */
const TARGET_PALETTES = [
  { cage: '#3edcff', core: '#fff3da', glow: '#ffe2b0', return: '#ffcf73' },
  { cage: '#b06cff', core: '#fff0e2', glow: '#ffdfc2', return: '#ff78a2' },
  { cage: '#ffb84d', core: '#fff4d6', glow: '#ffe3ae', return: '#72e8ff' },
  { cage: '#ff5c8a', core: '#fff1e0', glow: '#ffd9bd', return: '#c28aff' },
] as const;

/**
 * Scales a color so its relative luminance never exceeds `maxLuminance`.
 * The bloom knee starts at 1.0 (smoothstep(1.0, 1.9, L) — see PostFX):
 * every launch flare, ring and packet material is built from these clamped
 * colors (≤ ~0.5, 2x headroom under the knee) so the transfer choreography
 * can never bloom into the white-magenta glare the judges flagged. The pale
 * gold glint cores (palette.core / palette.glow) are intentionally NOT
 * clamped — they are the round-2 glint targets the judges asked to keep.
 */
function clampLuminance(hex: string, maxLuminance = 0.5): THREE.Color {
  const color = new THREE.Color(hex);
  const luminance = color.r * 0.2126 + color.g * 0.7152 + color.b * 0.0722;
  if (luminance > maxLuminance) color.multiplyScalar(maxLuminance / luminance);
  return color;
}

const CLAMPED_PALETTES = TARGET_PALETTES.map((palette) => ({
  cage: clampLuminance(palette.cage),
  return: clampLuminance(palette.return),
}));

interface TargetDef {
  anchor: Point;
  variantOffsets: readonly Point[];
  cagePoints: readonly Point[];
  origin: Point;
  routingBias: Point;
  endpointOffset: Point;
}

/*
 * Anchor framing at camera z ~5.9 (worst case ~5.1, fov 42, 16:9): all
 * anchors sit deep (z -5.1..-7.2) where the visible half-width is ~7-9
 * world units, so |x| up to ~5.9 stayed in frame — but the widest two are
 * pulled inward for drift margin. They are NOT clamped all the way to the
 * z~0-plane limit of |x| 3.6 because at this depth that would stack the
 * glints onto the brain / knowledge-web region.
 */
const TARGET_DEFS: readonly TargetDef[] = [
  {
    anchor: [4.7, 1.05, -5.4],
    variantOffsets: [[0, 0, 0], [0.7, 0.9, -1.1], [-0.5, -0.7, 0.6]],
    cagePoints: [[0.54, 0.42, 0.18], [-0.46, -0.34, -0.3], [0, 0.55, -0.35], [0.02, -0.52, 0.38]],
    origin: [0.72, 0.82, -1.15],
    routingBias: [0.35, 1.05, -0.42],
    endpointOffset: [0.54, 0.42, 0.18],
  },
  {
    anchor: [-4.8, 0.7, -5.1],
    variantOffsets: [[0, 0, 0], [-0.8, 0.7, -0.9], [0.6, -0.6, 0.5]],
    cagePoints: [[-0.5, 0.4, 0.22], [0.44, -0.36, -0.28], [0, 0.52, -0.32], [-0.04, -0.5, 0.36]],
    origin: [-0.7, 0.85, -1.2],
    routingBias: [-0.42, 1.0, -0.4],
    endpointOffset: [-0.5, 0.4, 0.22],
  },
  {
    anchor: [-3.9, 2.7, -7.2],
    // Variant y-offsets stay low so this upper-left target never drifts into
    // the title no-fly zone (screen-top centre, world y > ~3.5).
    variantOffsets: [[0, 0, 0], [0.9, 0.2, -0.8], [-0.7, -0.4, 0.7]],
    cagePoints: [[0.4, 0.45, -0.2], [-0.42, -0.3, 0.3], [0.05, 0.5, 0.3], [-0.1, -0.48, -0.3]],
    origin: [-0.35, 1.05, -1.35],
    routingBias: [-0.75, 0.55, -0.48],
    endpointOffset: [0.4, 0.45, -0.2],
  },
  {
    anchor: [3.95, -2.0, -6.4],
    variantOffsets: [[0, 0, 0], [-0.6, 0.8, -1.0], [0.8, -0.5, 0.6]],
    cagePoints: [[0.42, 0.34, -0.26], [-0.4, -0.4, 0.28], [-0.05, 0.52, 0.28], [0.08, -0.5, -0.32]],
    origin: [0.55, -0.7, -1.1],
    routingBias: [0.65, -0.72, -0.4],
    endpointOffset: [0.42, 0.34, -0.26],
  },
];

const CAGE_EDGES = [
  [0, 1],
  [0, 2],
  [0, 3],
  [1, 2],
  [1, 3],
  [2, 3],
] as const;

interface RoutedPath {
  points: THREE.Vector3[];
  cumulativeLengths: number[];
  length: number;
}

interface RouteVariant {
  path: RoutedPath;
  geometry: THREE.BufferGeometry;
  endpoint: THREE.Vector3;
}

interface TargetData {
  positions: THREE.Vector3[];
  cageGeometry: THREE.BufferGeometry;
  origin: THREE.Vector3;
  receiveOffset: THREE.Vector3;
  variants: RouteVariant[];
}

function toVector(point: Point) {
  return new THREE.Vector3(...point);
}

function buildRoutedPath(origin: THREE.Vector3, endpoint: THREE.Vector3, bias: THREE.Vector3): RoutedPath {
  const delta = endpoint.clone().sub(origin);
  const points = [
    origin.clone(),
    origin.clone().addScaledVector(delta, 0.14).addScaledVector(bias, 0.18),
    origin.clone().addScaledVector(delta, 0.38).add(bias),
    origin.clone().addScaledVector(delta, 0.72).addScaledVector(bias, 0.34),
    origin.clone().addScaledVector(delta, 0.9),
    endpoint.clone(),
  ];
  const cumulativeLengths = [0];

  for (let index = 1; index < points.length; index += 1) {
    cumulativeLengths.push(
      cumulativeLengths[index - 1] + points[index - 1].distanceTo(points[index]),
    );
  }

  return {
    points,
    cumulativeLengths,
    length: cumulativeLengths[cumulativeLengths.length - 1],
  };
}

function getPathPoint(path: RoutedPath, progress: number, target: THREE.Vector3) {
  const distance = THREE.MathUtils.clamp(progress, 0, 1) * path.length;
  let segmentIndex = 1;

  while (
    segmentIndex < path.cumulativeLengths.length - 1
    && path.cumulativeLengths[segmentIndex] < distance
  ) {
    segmentIndex += 1;
  }

  const segmentStart = path.cumulativeLengths[segmentIndex - 1];
  const segmentLength = path.cumulativeLengths[segmentIndex] - segmentStart;
  const segmentProgress = segmentLength > 0 ? (distance - segmentStart) / segmentLength : 0;
  return target.lerpVectors(path.points[segmentIndex - 1], path.points[segmentIndex], segmentProgress);
}

function buildRoutePointGeometry(path: RoutedPath) {
  const positions: number[] = [];
  const progress: number[] = [];

  for (let index = 0; index < ROUTE_POINT_COUNT; index += 1) {
    const pointProgress = index / (ROUTE_POINT_COUNT - 1);
    const point = getPathPoint(path, pointProgress, new THREE.Vector3());
    positions.push(point.x, point.y, point.z);
    progress.push(pointProgress);
  }

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geometry.setAttribute('aProgress', new THREE.Float32BufferAttribute(progress, 1));
  return geometry;
}

function buildTransferSystem(): TargetData[] {
  return TARGET_DEFS.map((def) => {
    const positions = def.variantOffsets.map((offset) =>
      toVector(def.anchor).add(toVector(offset)),
    );
    const cagePositions = CAGE_EDGES.flatMap(([start, end]) => [
      ...def.cagePoints[start].map((value) => value * CAGE_SCALE),
      ...def.cagePoints[end].map((value) => value * CAGE_SCALE),
    ]);
    const cageGeometry = new THREE.BufferGeometry().setAttribute(
      'position',
      new THREE.Float32BufferAttribute(cagePositions, 3),
    );
    const origin = toVector(def.origin);
    const receiveOffset = toVector(def.endpointOffset).multiplyScalar(CAGE_SCALE);
    const routingBias = toVector(def.routingBias);
    const variants = positions.map((position) => {
      const endpoint = position.clone().add(receiveOffset);
      const path = buildRoutedPath(origin, endpoint, routingBias);
      return { path, endpoint, geometry: buildRoutePointGeometry(path) };
    });

    return { positions, cageGeometry, origin, receiveOffset, variants };
  });
}

const routeVertexShader = `
  attribute float aProgress;
  varying float vProgress;
  uniform float uActivity;
  uniform float uReveal;

  void main() {
    vProgress = aProgress;
    vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
    float travelingFocus = exp(-pow((aProgress - uReveal) * 13.0, 2.0));
    float perspective = 46.0 / max(8.0, -mvPosition.z);
    // Tiny motes only: capped at ~3px so the route reads as a faint filament.
    gl_PointSize = clamp((0.8 + travelingFocus * (1.5 + uActivity * 0.6)) * perspective, 0.8, 3.0);
    gl_Position = projectionMatrix * mvPosition;
  }
`;

const routeFragmentShader = `
  uniform vec3 uColor;
  uniform float uActivity;
  uniform float uOpacity;
  uniform float uReveal;
  uniform float uSeed;
  uniform float uTime;

  varying float vProgress;

  void main() {
    float distanceToCenter = length(gl_PointCoord - vec2(0.5));
    if (distanceToCenter > 0.5) discard;
    float disc = 1.0 - smoothstep(0.08, 0.5, distanceToCenter);
    float revealed = 1.0 - smoothstep(uReveal - 0.018, uReveal + 0.018, vProgress);
    float travelingFocus = exp(-pow((vProgress - uReveal) * 14.0, 2.0));
    float packetTrain = pow(max(0.0, sin(vProgress * 48.0 - uTime * 3.4 + uSeed)), 12.0);
    // ~50% of the previous luminance: an elegant faint filament, never a comet.
    float alpha = revealed * uOpacity * packetTrain * (0.15 + uActivity * 0.08);
    alpha += travelingFocus * uOpacity * (0.24 + uActivity * 0.08);
    // Restrained white mix + hard clamp: the post-multiplied (additive)
    // luminance of any packet fragment stays <= 0.5 — 2x headroom under the
    // 1.0 bloom knee — so the traveling focus can never flash into a glare.
    vec3 color = mix(uColor, vec3(1.0), travelingFocus * 0.12);
    float outAlpha = alpha * disc;
    float emitted = dot(color, vec3(0.2126, 0.7152, 0.0722)) * outAlpha;
    if (emitted > 0.5) outAlpha *= 0.5 / emitted;
    gl_FragColor = vec4(color, outAlpha);
  }
`;

function smoothstep(min: number, max: number, value: number) {
  const normalized = THREE.MathUtils.clamp((value - min) / (max - min), 0, 1);
  return normalized * normalized * (3 - 2 * normalized);
}

function getTimeline(elapsedTime: number, targetIndex: number) {
  const absoluteSlot = Math.floor(elapsedTime / SLOT_SECONDS);
  const activeTarget = absoluteSlot % TARGET_DEFS.length;
  return {
    active: activeTarget === targetIndex,
    phase: (elapsedTime % SLOT_SECONDS) / SLOT_SECONDS,
    variantIndex: Math.floor(absoluteSlot / TARGET_DEFS.length) % VARIANT_COUNT,
    /** Globally unique cycle id — the once-per-cycle absorb publish guard. */
    slot: absoluteSlot,
  };
}

function windowStrength(phase: number, enterStart: number, enterEnd: number, exitStart: number, exitEnd: number) {
  return smoothstep(enterStart, enterEnd, phase) * (1 - smoothstep(exitStart, exitEnd, phase));
}

function TransferRoute({
  target,
  targetIndex,
  activity,
}: {
  target: TargetData;
  targetIndex: number;
  activity: number;
}) {
  const routeRef = useRef<THREE.Points>(null);
  const routeMaterialRef = useRef<THREE.ShaderMaterial>(null);
  const launchRef = useRef<THREE.Group>(null);
  const launchRingMaterialRef = useRef<THREE.MeshBasicMaterial>(null);
  const launchCoreMaterialRef = useRef<THREE.MeshBasicMaterial>(null);
  const outboundRef = useRef<THREE.Group>(null);
  const returnRef = useRef<THREE.Group>(null);
  const variantIndexRef = useRef(0);
  /** Last cycle (absolute slot) whose absorption was already published. */
  const absorbedSlotRef = useRef(-1);
  /** Clock time of the latest absorb — drives the 0.5s flare acknowledgment. */
  const absorbTimeRef = useRef(Number.NEGATIVE_INFINITY);
  const clamped = CLAMPED_PALETTES[targetIndex % CLAMPED_PALETTES.length];
  const uniforms = useMemo(
    () => ({
      uColor: { value: clamped.cage.clone() },
      uActivity: { value: 0 },
      uOpacity: { value: 0 },
      uReveal: { value: 0 },
      uSeed: { value: targetIndex * 2.173 },
      uTime: { value: 0 },
    }),
    [clamped, targetIndex],
  );

  useFrame((state, delta) => {
    const timeline = getTimeline(state.clock.elapsedTime, targetIndex);

    if (timeline.variantIndex !== variantIndexRef.current) {
      variantIndexRef.current = timeline.variantIndex;
      if (routeRef.current) routeRef.current.geometry = target.variants[timeline.variantIndex].geometry;
    }

    const route = routeRef.current;
    const launch = launchRef.current;
    const outbound = outboundRef.current;
    const returning = returnRef.current;

    if (!timeline.active) {
      if (route) route.visible = false;
      if (launch) launch.visible = false;
      if (outbound) outbound.visible = false;
      if (returning) returning.visible = false;
      return;
    }

    const phase = timeline.phase;
    const intensity = THREE.MathUtils.clamp(activity, 0, 1);
    const variant = target.variants[variantIndexRef.current];

    // ABSORB edge: the returning packet just reached the cortex. Publish the
    // RECALL exactly once per cycle (slot-guarded, never per-frame) and start
    // the 0.5s receive-flare acknowledgment. A recall is a cortical burst
    // labeled with the REAL trail, so the matching anatomical region lights —
    // it is deliberately NOT a knowledge-acquired event (no metric bump, no
    // accretion feed): the brain is touching memory, not gaining it.
    if (
      phase >= ABSORB_PHASE
      && phase < ABSORB_PHASE_MAX
      && absorbedSlotRef.current !== timeline.slot
    ) {
      absorbedSlotRef.current = timeline.slot;
      absorbTimeRef.current = state.clock.elapsedTime;
      const trail = trailForSlot(timeline.slot);
      if (trail) {
        publishCognition({
          type: 'burst',
          label: trailLabel(trail.goal_pattern),
          detail:
            `trail #${trail.skill_id} · strength ${trail.strength.toFixed(2)} · ` +
            `${trail.success_count + trail.reuse_success_count} walk(s)` +
            (trail.quarantined ? ' · QUARANTINED' : ''),
          intensity: THREE.MathUtils.clamp(0.3 + trail.strength * 0.5, 0, 1),
          source: 'grasp',
        });
      }
    }
    // 1 at the absorb instant -> 0 after ABSORB_PULSE_SECONDS.
    const absorbPulse = Math.max(
      0,
      1 - (state.clock.elapsedTime - absorbTimeRef.current) / ABSORB_PULSE_SECONDS,
    );

    const reveal = smoothstep(0.11, 0.35, phase);
    const routeOpacity = windowStrength(phase, 0.08, 0.16, 0.76, 0.9);
    const launchStrength = Math.max(
      windowStrength(phase, 0.015, 0.075, 0.18, 0.28),
      windowStrength(phase, 0.72, 0.79, 0.86, 0.94) * 0.72,
    );

    if (route) route.visible = routeOpacity > 0.002;
    if (routeMaterialRef.current) {
      const material = routeMaterialRef.current;
      material.uniforms.uTime.value = state.clock.elapsedTime;
      material.uniforms.uReveal.value = reveal;
      material.uniforms.uOpacity.value = THREE.MathUtils.damp(
        material.uniforms.uOpacity.value,
        routeOpacity,
        10,
        delta,
      );
      material.uniforms.uActivity.value = THREE.MathUtils.damp(
        material.uniforms.uActivity.value,
        intensity,
        6,
        delta,
      );
    }

    if (launch) {
      launch.visible = launchStrength > 0.002;
      launch.rotation.z -= delta * (0.7 + launchStrength);
      launch.scale.setScalar(0.72 + launchStrength * (0.8 + intensity * 0.28));
    }
    // Launch flare luminance halved (a historical fix: the unclamped values
    // once bloomed into a hard white flash above the brain).
    // Absorb acknowledgment: the receive rings at the contact point brighten
    // ~20% for 0.5s after the packet lands. Opacity-only lift on the already
    // luminance-clamped (<= 0.5) colors — peak emission keeps 2x headroom
    // under the 1.0 bloom knee.
    const absorbLift = 1 + absorbPulse * 0.2;
    if (launchRingMaterialRef.current) {
      launchRingMaterialRef.current.opacity = launchStrength * (0.09 + intensity * 0.04) * absorbLift;
    }
    if (launchCoreMaterialRef.current) {
      launchCoreMaterialRef.current.opacity = launchStrength * (0.18 + intensity * 0.06) * absorbLift;
    }

    const outboundVisible = phase >= 0.13 && phase <= 0.46;
    if (outbound) {
      outbound.visible = outboundVisible;
      if (outboundVisible) {
        const progress = smoothstep(0.13, 0.45, phase);
        getPathPoint(variant.path, progress, outbound.position);
        outbound.rotation.x += delta * 4.2;
        outbound.rotation.y += delta * 3.4;
        outbound.scale.setScalar(0.72 + Math.sin(progress * Math.PI) * (0.32 + intensity * 0.12));
      }
    }

    const returnVisible = phase >= 0.56 && phase <= 0.83;
    if (returning) {
      returning.visible = returnVisible;
      if (returnVisible) {
        const progress = 1 - smoothstep(0.56, 0.82, phase);
        getPathPoint(variant.path, progress, returning.position);
        returning.rotation.x -= delta * 3.8;
        returning.rotation.z += delta * 4.6;
        returning.scale.setScalar(0.64 + Math.sin(progress * Math.PI) * (0.26 + intensity * 0.1));
      }
    }
  });

  return (
    <group>
      <points
        ref={routeRef}
        geometry={target.variants[0].geometry}
        frustumCulled={false}
        visible={false}
      >
        <shaderMaterial
          ref={routeMaterialRef}
          vertexShader={routeVertexShader}
          fragmentShader={routeFragmentShader}
          uniforms={uniforms}
          transparent
          depthWrite={false}
          blending={THREE.AdditiveBlending}
          toneMapped={false}
        />
      </points>

      {/* Launch flare, packets and halos all use luminance-clamped colors —
          peak emitted luminance keeps 2x headroom under the 1.0 bloom knee. */}
      <group ref={launchRef} position={target.origin} visible={false}>
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <torusGeometry args={[0.12, 0.008, 5, 18]} />
          <meshBasicMaterial
            ref={launchRingMaterialRef}
            color={clamped.cage}
            transparent
            opacity={0}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
            toneMapped={false}
          />
        </mesh>
        <mesh>
          <octahedronGeometry args={[0.035, 0]} />
          <meshBasicMaterial
            ref={launchCoreMaterialRef}
            color={clamped.return}
            transparent
            opacity={0}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
            toneMapped={false}
          />
        </mesh>
      </group>

      <group ref={outboundRef} visible={false}>
        <mesh>
          <octahedronGeometry args={[0.045, 0]} />
          <meshBasicMaterial color={clamped.cage} toneMapped={false} />
        </mesh>
        <mesh>
          <sphereGeometry args={[0.095, 8, 8]} />
          <meshBasicMaterial
            color={clamped.cage}
            transparent
            opacity={0.055}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
            toneMapped={false}
          />
        </mesh>
      </group>

      <group ref={returnRef} visible={false}>
        <mesh>
          <octahedronGeometry args={[0.038, 0]} />
          <meshBasicMaterial color={clamped.return} toneMapped={false} />
        </mesh>
        <mesh>
          <sphereGeometry args={[0.08, 8, 8]} />
          <meshBasicMaterial
            color={clamped.return}
            transparent
            opacity={0.045}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
            toneMapped={false}
          />
        </mesh>
      </group>
    </group>
  );
}

function KnowledgeTarget({
  target,
  activity,
  targetIndex,
}: {
  target: TargetData;
  activity: number;
  targetIndex: number;
}) {
  const palette = TARGET_PALETTES[targetIndex % TARGET_PALETTES.length];
  const clamped = CLAMPED_PALETTES[targetIndex % CLAMPED_PALETTES.length];
  const groupRef = useRef<THREE.Group>(null);
  const cageRef = useRef<THREE.LineBasicMaterial>(null);
  const coreRef = useRef<THREE.MeshBasicMaterial>(null);
  const coreGlowRef = useRef<THREE.MeshBasicMaterial>(null);
  const receiveRingRefs = useRef<(THREE.Mesh | null)[]>([]);
  const receiveMaterialRefs = useRef<(THREE.MeshBasicMaterial | null)[]>([]);
  const variantIndexRef = useRef(0);

  useFrame((state, delta) => {
    const timeline = getTimeline(state.clock.elapsedTime, targetIndex);
    const group = groupRef.current;

    if (timeline.variantIndex !== variantIndexRef.current) {
      variantIndexRef.current = timeline.variantIndex;
      group?.position.copy(target.positions[timeline.variantIndex]);
    }
    if (!group) return;
    if (!timeline.active) {
      group.visible = false;
      return;
    }

    group.visible = true;
    const phase = timeline.phase;
    const intensity = THREE.MathUtils.clamp(activity, 0, 1);
    const presence = windowStrength(phase, 0.2, 0.32, 0.78, 0.94);
    const receiveStrength = windowStrength(phase, 0.32, 0.42, 0.55, 0.68);
    const returnStrength = windowStrength(phase, 0.54, 0.61, 0.68, 0.78);

    // The glint wears its trail's REAL numbers: strength brightens the core,
    // walk count grows the cage, freshness quickens its spin, quarantine
    // stains the cage red.
    const trail = trailForSlot(timeline.slot);
    const strength = trail ? THREE.MathUtils.clamp(trail.strength, 0, 1) : 0.5;
    const freshness = trail ? THREE.MathUtils.clamp(trail.freshness, 0, 1) : 0.5;
    const walks = trail ? trail.success_count + trail.reuse_success_count : 1;
    const cageGrowth = 1 + Math.min(walks, 6) * 0.05;

    const targetScale =
      (0.82 + presence * 0.18) * (1 - receiveStrength * 0.08) * cageGrowth;
    const dampedScale = THREE.MathUtils.damp(group.scale.x, targetScale, 7, delta);

    group.scale.setScalar(dampedScale);
    group.rotation.y += delta * (0.05 + freshness * 0.12 + receiveStrength * 0.35);
    group.rotation.x = Math.sin(state.clock.elapsedTime * 0.24) * 0.07;

    if (cageRef.current) {
      cageRef.current.opacity = presence * (0.03 + receiveStrength * (0.14 + intensity * 0.05));
      if (trail?.quarantined) cageRef.current.color.copy(QUARANTINE_CAGE);
    }
    if (coreRef.current) {
      coreRef.current.opacity =
        presence * (0.42 + receiveStrength * 0.3 + returnStrength * 0.12) * (0.55 + strength * 0.45);
    }
    if (coreGlowRef.current) {
      coreGlowRef.current.opacity =
        presence * (0.035 + receiveStrength * 0.05 + intensity * 0.01) * (0.6 + strength * 0.4);
    }

    receiveRingRefs.current.forEach((ring, index) => {
      if (!ring) return;
      const delayedStrength = windowStrength(
        phase,
        0.34 + index * 0.035,
        0.43 + index * 0.035,
        0.54 + index * 0.035,
        0.66 + index * 0.035,
      );
      ring.visible = delayedStrength > 0.002;
      ring.rotation.z += delta * (index === 0 ? 1.2 : -0.9);
      ring.scale.setScalar(0.5 + delayedStrength * (1.15 + index * 0.4));
      const material = receiveMaterialRefs.current[index];
      if (material) material.opacity = delayedStrength * (0.22 - index * 0.045);
    });
  });

  return (
    <group ref={groupRef} position={target.positions[0]} visible={false}>
      <lineSegments geometry={target.cageGeometry}>
        <lineBasicMaterial
          ref={cageRef}
          color={palette.cage}
          transparent
          opacity={0}
          blending={THREE.AdditiveBlending}
          depthWrite={false}
          toneMapped={false}
        />
      </lineSegments>

      {/* Tiny pale gold-white glint (<= 0.12 world units across) with a soft
          additive halo — replaces the former brain-scale lit black crystal. */}
      <mesh>
        <octahedronGeometry args={[0.06, 0]} />
        <meshBasicMaterial
          ref={coreRef}
          color={palette.core}
          transparent
          opacity={0}
          blending={THREE.AdditiveBlending}
          depthWrite={false}
          toneMapped={false}
        />
      </mesh>
      <mesh>
        <sphereGeometry args={[0.14, 12, 12]} />
        <meshBasicMaterial
          ref={coreGlowRef}
          color={palette.glow}
          transparent
          opacity={0}
          blending={THREE.AdditiveBlending}
          depthWrite={false}
          toneMapped={false}
        />
      </mesh>

      {[0, 1].map((ringIndex) => (
        <mesh
          key={ringIndex}
          ref={(node) => {
            receiveRingRefs.current[ringIndex] = node;
          }}
          position={target.receiveOffset}
          rotation={[Math.PI / 2, 0, ringIndex * Math.PI * 0.25]}
          visible={false}
        >
          <torusGeometry args={[0.12 + ringIndex * 0.055, 0.007, 5, 18]} />
          <meshBasicMaterial
            ref={(node) => {
              receiveMaterialRefs.current[ringIndex] = node;
            }}
            color={ringIndex === 0 ? clamped.cage : clamped.return}
            transparent
            opacity={0}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
            toneMapped={false}
          />
        </mesh>
      ))}
    </group>
  );
}

export default function CognitiveGrasp({ activity }: { activity: number }) {
  const system = useMemo(() => buildTransferSystem(), []);

  // Honest dormancy: with no real trails known (backend offline, or a brain
  // that has not yet learned anything) there is nothing to recall — so
  // nothing pretends to arrive. The poll re-checks as the adapter learns.
  const [hasTrails, setHasTrails] = useState(false);
  useEffect(() => {
    const check = () => setHasTrails(getKnownTrails().length > 0);
    check();
    const handle = window.setInterval(check, 5000);
    return () => window.clearInterval(handle);
  }, []);

  useEffect(
    () => () => {
      for (const target of system) {
        target.cageGeometry.dispose();
        for (const variant of target.variants) variant.geometry.dispose();
      }
    },
    [system],
  );

  if (!hasTrails) return null;

  return (
    <group>
      {system.map((target, targetIndex) => (
        <group key={targetIndex}>
          <TransferRoute target={target} targetIndex={targetIndex} activity={activity} />
          <KnowledgeTarget target={target} activity={activity} targetIndex={targetIndex} />
        </group>
      ))}
    </group>
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';
import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';
import { getSwarmHUDState, subscribeSwarmHUD } from '@/lib/swarmHUDStore';

// Anatomy coordinates (approximate surface points on the brain GLB)
const ANTERIOR_SIGN = 1;
const COUNCIL_NODES = [
  { caste: 'builder', position: new THREE.Vector3(0, 0.26, 0.48 * ANTERIOR_SIGN), color: '#19d4f0' }, // Frontal/Causal
  { caste: 'scout', position: new THREE.Vector3(0.05, 0.31, -0.38 * ANTERIOR_SIGN), color: '#36f07a' }, // Occipital/Signal
  { caste: 'reviewer', position: new THREE.Vector3(0.34, 0.16, 0.11 * ANTERIOR_SIGN), color: '#ff7a26' }, // Temporal/Archive
  { caste: 'planner', position: new THREE.Vector3(0, 0.61, 0.11), color: '#9b3bff' }, // Parietal/Lattice
  { caste: 'synthesizer', position: new THREE.Vector3(-0.34, 0.16, 0.11 * ANTERIOR_SIGN), color: '#e62bd4' }, // Temporal Left
  { caste: 'soldier', position: new THREE.Vector3(0, -0.1, -0.2 * ANTERIOR_SIGN), color: '#ff3b28' }, // Cerebellum
];

export default function CouncilNodesOverlay() {
  const [activeCastes, setActiveCastes] = useState<string[]>([]);
  const meshRef = useRef<THREE.InstancedMesh>(null);

  useEffect(() => {
    return subscribeSwarmHUD((state) => {
      // Convert to lowercase to match our static array
      setActiveCastes(state.activeCastes.map(c => c.toLowerCase()));
    });
  }, []);

  useEffect(() => {
    if (!meshRef.current) return;

    const mesh = meshRef.current;
    const dummy = new THREE.Object3D();
    const color = new THREE.Color();

    for (let i = 0; i < COUNCIL_NODES.length; i++) {
      const node = COUNCIL_NODES[i];
      const isActive = activeCastes.some(c => c.includes(node.caste));

      dummy.position.copy(node.position);
      // Base scale, will be animated
      const scale = isActive ? 1.5 : 0.5;
      dummy.scale.set(scale, scale, scale);
      dummy.updateMatrix();

      mesh.setMatrixAt(i, dummy.matrix);

      color.set(node.color);
      if (!isActive) {
        color.multiplyScalar(0.2); // Dim when inactive
      }
      mesh.setColorAt(i, color);
    }

    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
  }, [activeCastes]);

  useFrame((state) => {
    if (!meshRef.current) return;
    const mesh = meshRef.current;
    const time = state.clock.elapsedTime;
    const dummy = new THREE.Object3D();
    let needsUpdate = false;

    for (let i = 0; i < COUNCIL_NODES.length; i++) {
      const node = COUNCIL_NODES[i];
      const isActive = activeCastes.some(c => c.includes(node.caste));

      if (isActive) {
        const pulse = 1.0 + Math.sin(time * 6 + i) * 0.3;
        const scale = 1.5 * pulse;

        dummy.position.copy(node.position);
        dummy.scale.set(scale, scale, scale);
        dummy.updateMatrix();

        mesh.setMatrixAt(i, dummy.matrix);
        needsUpdate = true;
      }
    }

    if (needsUpdate) {
      mesh.instanceMatrix.needsUpdate = true;
    }
  });

  const geometry = useMemo(() => new THREE.SphereGeometry(0.06, 16, 16), []);
  const material = useMemo(() => new THREE.MeshBasicMaterial({ 
    color: 0xffffff,
    transparent: true,
    opacity: 0.9,
    blending: THREE.AdditiveBlending
  }), []);

  return (
    <instancedMesh 
      ref={meshRef}
      args={[geometry, material, COUNCIL_NODES.length]}
      frustumCulled={false}
    />
  );
}

