              <sphereGeometry args={[1, 14, 8]} />
              <meshBasicMaterial
                color={coreColor}
                transparent
                opacity={Math.min(0.56, skin.nodeOpacity * material.tissue.rootGripGain * mark.intensity * 1.2)}
                depthWrite={false}
