const ROOT_DROOP_GROWTH = 1.6;       // downward sag at the bottom (the weeping-willow hang)
const ROOT_RADIUS_TOP = 0.018;       // root tube RADIUS at the top segment (thin thread)
const ROOT_RADIUS_BOTTOM = 0.05;     // root tube RADIUS at the bottom segment (fuller)
const ROOT_FLARE = 0.7;              // radius gain toward the weeping tip: r(t)=base*(0.6+ROOT_FLARE*t)
const ROOT_RADIAL_SEGMENTS = 12;     // roots are thin + numerous → low radial count (still reads round)
const ROOT_TUBE_SEGMENTS = 28;       // arc subdivisions along a root

// --- Cauda-equina SPRAY (the terminal downward willow flourish) ---
const SPRAY_COUNT: number = 16;      // # of strands fanned across the spray
const SPRAY_FAN_WIDTH = 1.05;        // half-width the spray fans to at its tips
const SPRAY_LENGTH_CENTER = 1.4;     // how far the CENTER spray fibre hangs below the conus (longest)
const SPRAY_LENGTH_EDGE = 1.0;       // how far the OUTER spray fibres hang (shorter → teardrop, not broom)
const SPRAY_RADIUS_TOP = 0.04;       // spray tube RADIUS at the conus (the willow's neck)
const SPRAY_RADIUS_TIP = 0.03;       // spray tube RADIUS at the tips (softest, broadest fan)
const SPRAY_RADIAL_SEGMENTS = 12;    // spray is thin → low radial count
const SPRAY_TUBE_SEGMENTS = 48;      // arc subdivisions along a spray filament

// ── ARC-RAMP COLOUR SAMPLER (brain palette, region down the body arc) ────────
const _tmpA = new THREE.Color();
const _tmpB = new THREE.Color();
const _hsl = { h: 0, s: 0, l: 0 };
function arcColor(
  random: () => number,
  arc: number,
  jitterHue = 0.06,
  target = new THREE.Color()
): THREE.Color {
  const a = THREE.MathUtils.clamp(arc, 0, 1);
  let lo = ARC_RAMP[0];
  let hi = ARC_RAMP[ARC_RAMP.length - 1];
  for (let k = 0; k < ARC_RAMP.length - 1; k++) {
    if (a >= ARC_RAMP[k].at && a <= ARC_RAMP[k + 1].at) {
      lo = ARC_RAMP[k];
      hi = ARC_RAMP[k + 1];
      break;
    }
  }
  const span = Math.max(hi.at - lo.at, 1e-4);
  const w = THREE.MathUtils.smoothstep((a - lo.at) / span, 0, 1);
  target.copy(_tmpA.copy(lo.color).lerp(_tmpB.copy(hi.color), w));
  // Small seeded per-vertex hue jitter so boundaries are organic, not banded.
  if (jitterHue > 0) {
    target.getHSL(_hsl);
    target.setHSL(
      (_hsl.h + (random() - 0.5) * jitterHue + 1) % 1,
      THREE.MathUtils.clamp(_hsl.s + (random() - 0.5) * 0.08, 0, 1),
      THREE.MathUtils.clamp(_hsl.l + (random() - 0.5) * 0.06, 0, 1)
    );
  }
  // Luminance floor — keep the dark ramp blends off pure black.
  const lum = target.r * 0.2126 + target.g * 0.7152 + target.b * 0.0722;
  if (lum > 1e-4 && lum < NERVE_LUMINANCE_FLOOR) {
    target.multiplyScalar(NERVE_LUMINANCE_FLOOR / lum);
  } else if (lum <= 1e-4) {
    target.copy(ARC_RAMP[0].color);
  }
  return target;
}

/**
 * Bake the nerve attributes onto a freshly-built geometry IN PLACE:
 *   • `objectPos` (vec3) = the raw group-local vertex position (continuity
 *      contract — the brain shader reads vLocalPos = objectPos * 2.0).
 *   • `color` (vec3) = the brain-palette arc-ramp colour for this vertex.
 *   • `aArc` (float) = position along the body 0..1 (drives the flow band).
 * `arcFn(localY, vertexIndex)` maps a vertex to its body-arc; for tubes built
 * along a descending curve we derive arc from Y, for vertebrae/roots we pass a
 * constant segment arc, and for the spray we span the strand's own length.
 */
function bakeNerveAttributes(
  geo: THREE.BufferGeometry,
  random: () => number,
  arcAt: (vx: number, vy: number, vz: number, i: number) => number,
  hueJitter = 0.04
) {
  const pos = geo.getAttribute('position');
  const count = pos.count;
  const objectPos = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);
  const arcs = new Float32Array(count);
  const c = new THREE.Color();
  for (let i = 0; i < count; i++) {
    const x = pos.getX(i);
    const y = pos.getY(i);
    const z = pos.getZ(i);
    // objectPos === the vertex position in the shared brain-group-local frame.
    objectPos[i * 3] = x;
    objectPos[i * 3 + 1] = y;
    objectPos[i * 3 + 2] = z;
    const arc = THREE.MathUtils.clamp(arcAt(x, y, z, i), 0, 1);
    arcs[i] = arc;
    arcColor(random, arc, hueJitter, c);
    colors[i * 3] = c.r;
    colors[i * 3 + 1] = c.g;
    colors[i * 3 + 2] = c.b;
  }
  geo.setAttribute('objectPos', new THREE.BufferAttribute(objectPos, 3));
  geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
  geo.setAttribute('aArc', new THREE.BufferAttribute(arcs, 1));
}

/** A radius-varying tube: TubeGeometry sweeps a CONSTANT radius, so we build it
 *  at radius 1 then scale each ring's cross-section by `radiusAt(t)` in-place.
 *  CatmullRom over the control points; `closed=false`, capped only where noted.
 *  Reproduces the cord/root/spray taper profiles exactly. */
function makeTaperedTube(
  points: THREE.Vector3[],
  tubularSegments: number,
  radialSegments: number,
  radiusAt: (t: number) => number,
  // GROWTH birth point each vertex collapses to before it is "born":
  //   'centerline' → its own ring centre (the tube materialises IN PLACE, thin→
  //                  full, downward) — used for the cord.
  //   Vector3      → a single origin (roots grow OUT from their cord attachment;
  //                  spray grows OUT from the conus).
  birthFrom: 'centerline' | THREE.Vector3 = 'centerline'
): THREE.TubeGeometry {
  const curve = new THREE.CatmullRomCurve3(points);
  const geo = new THREE.TubeGeometry(curve, tubularSegments, 1, radialSegments, false);
  const pos = geo.getAttribute('position') as THREE.BufferAttribute;
  const ringVerts = radialSegments + 1; // TubeGeometry emits (radial+1) verts per ring, (tubular+1) rings
  const birth = new Float32Array(pos.count * 3);
  // TubeGeometry places ring i at curve.getPoint(i/tubular) (uniform-t, NOT
  // arc-length) with a unit-circle cross-section, so |vert - center| == 1.
  // Scaling that offset by radiusAt(t) sets the ring radius — must use the SAME
  // getPoint(t) the geometry used or the offset won't be a clean unit vector.
  const center = new THREE.Vector3();
  const vert = new THREE.Vector3();
  const off = new THREE.Vector3();
  for (let i = 0; i <= tubularSegments; i++) {
    const t = tubularSegments === 0 ? 0 : i / tubularSegments;
    curve.getPoint(t, center);
    const r = radiusAt(t);
    for (let j = 0; j < ringVerts; j++) {
      const idx = i * ringVerts + j;
      vert.fromBufferAttribute(pos, idx);
      off.subVectors(vert, center).multiplyScalar(r);
      pos.setXYZ(idx, center.x + off.x, center.y + off.y, center.z + off.z);
      if (birthFrom === 'centerline') {
        birth[idx * 3] = center.x;
        birth[idx * 3 + 1] = center.y;
        birth[idx * 3 + 2] = center.z;
      } else {
        birth[idx * 3] = birthFrom.x;
        birth[idx * 3 + 1] = birthFrom.y;
        birth[idx * 3 + 2] = birthFrom.z;
      }
    }
  }
  pos.needsUpdate = true;
  geo.setAttribute('aBirth', new THREE.BufferAttribute(birth, 3));
  geo.computeVertexNormals();
  return geo;
}

/** Bake a CONSTANT birth point onto every vertex (used for the vertebra tori:
 *  the ring collapses to its spine anchor, then blooms OUT of the cord as the
 *  growth front reaches it). */
function bakeBirthConstant(geo: THREE.BufferGeometry, point: THREE.Vector3) {
  const count = geo.getAttribute('position').count;
  const birth = new Float32Array(count * 3);
  for (let i = 0; i < count; i++) {
    birth[i * 3] = point.x;
    birth[i * 3 + 1] = point.y;
    birth[i * 3 + 2] = point.z;
  }
  geo.setAttribute('aBirth', new THREE.BufferAttribute(birth, 3));
}

const NERVE_ATTRIBUTE_NAMES = [
  'position',
  'normal',
  'uv',
  'objectPos',
  'color',
  'aArc',
  'aBirth',
] as const;

function assertNerveAttributeSet(geo: THREE.BufferGeometry, label: string) {
  const attrs = Object.keys(geo.attributes).sort();
  const expected = [...NERVE_ATTRIBUTE_NAMES].sort();
  const missing = expected.filter((name) => !attrs.includes(name));
  const extra = attrs.filter((name) => !expected.includes(name as (typeof NERVE_ATTRIBUTE_NAMES)[number]));
  console.assert(
    missing.length === 0 && extra.length === 0,
    `Nerve geometry attribute mismatch in ${label}`,
    { missing, extra, attrs }
  );
}

export default function NervousSystem({
  burst,
  uniforms,
  tier = 'high',
  reducedMotion = false,
}: {
  burst: BurstRef;
  uniforms: CognitionUniforms;
  tier?: QualityTier;
  reducedMotion?: boolean;
}) {
  const groupRef = useRef<THREE.Group>(null);

  // Perfect synchronization with the brain's physical sway (sibling group, same
  // transform → cancels relative drift; the CNS moves as one body).
  useFrame((state) => {
    if (!groupRef.current) return;
    const time = state.clock.elapsedTime;
    groupRef.current.position.x = Math.sin(time * 0.16) * 0.24 + Math.cos(time * 0.09) * 0.1;
    groupRef.current.position.y = 0.12 + Math.cos(time * 0.2) * 0.14 + Math.sin(time * 0.14) * 0.07;
    groupRef.current.position.z = -1.2;
  });

  // The BRAIN'S EXACT material — Voronoi neural-web + region/palette vertex
  // colours + luminance ladder + fresnel glow, pulsing on the SAME shared
  // uTime/uHold/uArrival/uIgnite leaves the cortex uses + uBreath, plus the
  // nerve-only downward flow band. bodyMode:'nerve' uses the SAME 0.6 cell size
  // (continuity) but a cheaper single-octave + 8-cell Voronoi (PERF). Tier-keyed.
  const material = useMemo(
    () =>
      makeBrainMaterial({
        tier,
        uniforms,
        bodyMode: 'nerve',
        // FINE cell size: the cord is a thin smooth tube (no gyri/sulci), so it
        // needs a much higher Voronoi frequency than the big folded cortex to
        // read as the same living flesh (seeds uNerveScale; live-tunable via
        // window.__NERVE). LOCKED at 24 after a browser sweep (12=leopard-coarse,
        // 18=good, 26=finest; 24 = brain-dense stipple without thin-tube shimmer).
        webScale: 24,
        webOctaves: 'tier', // high tier gets brain-parity two-octave texture; lower tiers stay single-octave
        breathUniform: uniforms.uBreath,
        flowUniform: NERVE_FLOW_UNIFORM,
        reduceMotionUniform: NERVE_REDUCEMOTION_UNIFORM,
        growUniform: NERVE_GROW_UNIFORM,
        flowGainUniform: NERVE_FLOWGAIN_UNIFORM,
        intakeFlowUniform: NERVE_INTAKE_UNIFORM,
        intakeGainUniform: NERVE_INTAKEGAIN_UNIFORM,
        replyWarmUniform: NERVE_REPLYWARM_UNIFORM,
      }),
    [uniforms, tier]
  );

  useEffect(() => {
    NERVE_INTAKEGAIN_UNIFORM.value = 0;
    NERVE_REPLYWARM_UNIFORM.value = 0;
    NERVE_INTAKE_UNIFORM.value = 0;
    return () => {
      NERVE_INTAKEGAIN_UNIFORM.value = 0;
      NERVE_REPLYWARM_UNIFORM.value = 0;
      NERVE_INTAKE_UNIFORM.value = 0;
    };
  }, []);

  useEffect(
    () =>
      subscribeCognition((event) => {
        if (event.type !== 'voice-speaking') return;
        const phase = String(event.data?.phase ?? '');
        const intensity = THREE.MathUtils.clamp(event.intensity ?? 0.72, 0.25, 1);
        if (phase === 'question') {
          NERVE_INTAKE_UNIFORM.value = 0;
          NERVE_INTAKEGAIN_UNIFORM.value = Math.max(NERVE_INTAKEGAIN_UNIFORM.value, intensity);
          return;
        }
        if (event.source === 'reply' && phase === 'reply-start') {
          NERVE_FLOW_UNIFORM.value = Math.floor(NERVE_FLOW_UNIFORM.value);
          NERVE_FLOWGAIN_UNIFORM.value = Math.max(NERVE_FLOWGAIN_UNIFORM.value, intensity);
          NERVE_REPLYWARM_UNIFORM.value = 1;
          return;
        }
        if (event.source === 'reply' && phase === 'reply') {
          NERVE_FLOWGAIN_UNIFORM.value = Math.max(NERVE_FLOWGAIN_UNIFORM.value, intensity);
          NERVE_REPLYWARM_UNIFORM.value = Math.max(NERVE_REPLYWARM_UNIFORM.value, 0.85);
          return;
        }
        if (event.source === 'reply' && phase === 'reply-complete') {
          NERVE_FLOWGAIN_UNIFORM.value = Math.max(NERVE_FLOWGAIN_UNIFORM.value, intensity * 0.75);
          NERVE_REPLYWARM_UNIFORM.value = Math.max(NERVE_REPLYWARM_UNIFORM.value, 0.6);
        }
      }),
    []
  );

  useEffect(() => {
    const mat = material;
    return () => {
      mat.dispose();
    };
  }, [material]);

  // Advance the per-frame uniform leaves (flow sweep, reduced motion). The brain
  // shader / SuperbrainScene are untouched — uFlow lives here.
  useFrame((state, delta) => {
    NERVE_REDUCEMOTION_UNIFORM.value =
      typeof window !== 'undefined' && window.matchMedia
        ? window.matchMedia('(prefers-reduced-motion: reduce)').matches
          ? 1
          : 0
        : 0;
    // Steady descent of the impulse + an extra burst-driven kick (a command
    // visibly travels down the body). Frozen amplitude under reduced motion is
    // handled in-shader; freeze the advance too so it isn't stuck mid-band.
    if (NERVE_REDUCEMOTION_UNIFORM.value < 0.5) {
      // Posture flow: the impulse descent rides uFlow — rest crawls (~0.6x),
      // streaming races (~1.8x) — so the cord's signal speed reads the live state.
      const flowK = 0.4 + uniforms.uFlow.value * 1.4;
      NERVE_FLOW_UNIFORM.value +=
        (delta / FLOW_PERIOD_S) * flowK + burst.current.intensity * FLOW_BURST_KICK * delta;
      if (NERVE_INTAKEGAIN_UNIFORM.value > 0.01) {
        NERVE_INTAKE_UNIFORM.value += delta / INTAKE_FLOW_PERIOD_S;
      }
    }
    // Steady at rest: the impulse band is only visible when the being is actually
    // thinking. Quick attack to the burst level, gentle ~1.4s release so a command
    // lingers as it travels, then the cord returns to a calm steady glow.
    NERVE_FLOWGAIN_UNIFORM.value = Math.max(
      THREE.MathUtils.clamp(burst.current.intensity, 0, 1),
      // Posture floor: think/stream show a faint STEADY traveling band even without
      // a discrete cognition burst; rest (flow 0.16) stays exactly calm (floor 0).
      Math.max(0, uniforms.uFlow.value - 0.16) * 0.42,
      NERVE_FLOWGAIN_UNIFORM.value - delta * 0.7
    );
    NERVE_INTAKEGAIN_UNIFORM.value = Math.max(0, NERVE_INTAKEGAIN_UNIFORM.value - delta * 1.35);
    NERVE_REPLYWARM_UNIFORM.value = Math.max(0, NERVE_REPLYWARM_UNIFORM.value - delta * 0.58);

    // GROWTH: the spine generates once on the being's birth — advances after the
    // brain has had a moment to coalesce, easing 0→1 over GROW_DURATION_S.
    nerveGrowElapsed += delta;
    const growT = Math.max(0, (nerveGrowElapsed - GROW_DELAY_S) / GROW_DURATION_S);
    NERVE_GROW_UNIFORM.value = Math.min(1, growT);
  });

  // ── Build the four merged mesh structures (static; curves are deterministic).
  //    All authored in brain-group-local space; objectPos/aArc/color baked per
  //    mesh; seed 0x57495245 preserved so the (light) jitter is stable. ────────
  const geometries = useMemo(() => {
    const random = createSeededRandom(0x57495245);

    // ── 1) BRAINSTEM BULGE + CORD → merged (1 draw call) ──────────────────────
    // The bulge bridges the brain mass (brain-bottom girth) into the cord girth
    // so they read as ONE body and tuck into the stem stub with no seam.
    // The brainstem rises UP INTO the brain's basal cavity (its wide top buried
    // inside the cortex) and necks down to the cord girth right as it clears the
    // brain underside — so the being reads as ONE continuous trunk emerging from
    // the opening, not a thin cord hung below a hollow.
    const stemPath = [
      new THREE.Vector3(0, CORD_TOP_Y + STEM_TOP_RISE, CORD_Z + 0.03),   // buried up inside the brain mass (fills the opening)
      new THREE.Vector3(0, CORD_TOP_Y + STEM_TOP_RISE * 0.45, CORD_Z + 0.01),
      new THREE.Vector3(0, CORD_TOP_Y - 0.06, CORD_Z - 0.02),            // at the brain underside — still broad
      new THREE.Vector3(0, CORD_TOP_Y - 0.50, CORD_Z - 0.05),           // necks into the thick cord just below the brain
    ];
    const stemGeo = makeTaperedTube(
      stemPath,
      STEM_TUBE_SEGMENTS,
      STEM_RADIAL_SEGMENTS,
      // stay broad through the upper half (filling the cavity), then neck to the
      // cord girth by the time it exits the brain underside.
      (t) => THREE.MathUtils.lerp(STEM_TOP_R, CORD_SIGMA, THREE.MathUtils.smoothstep(t, 0.42, 0.82))
    );
    const stemYTop = CORD_TOP_Y + STEM_TOP_RISE;
    const stemYBot = CORD_TOP_Y - 0.50;
    bakeNerveAttributes(stemGeo, random, (_x, y) => {
      // map the stem's Y into the very top of the body arc (stem-violet band)
      const f = THREE.MathUtils.clamp((stemYTop - y) / Math.max(stemYTop - stemYBot, 1e-4), 0, 1);
      return f * 0.04; // arc 0..0.04 — cerebellum stem violet, matches the brain base
    });

    const cordSpine = [
      new THREE.Vector3(0.0, CORD_TOP_Y, CORD_Z),              // born AT the brainstem-stub bottom (seamless)
      new THREE.Vector3(0.0, CORD_STEM_EXIT_Y, CORD_Z - 0.06), // the stem-to-cord transition zone
      new THREE.Vector3(0.0, -1.5, CORD_Z - 0.04),             // upper cord — slight forward bow
      new THREE.Vector3(0.0, -2.15, CORD_Z + 0.02),            // mid cord
      new THREE.Vector3(0.0, -2.8, CORD_Z - 0.02),             // lower cord
      new THREE.Vector3(0.0, CORD_BOTTOM_Y, CORD_Z),           // conus tip — spray origin
    ];
    const cordGeo = makeTaperedTube(
      cordSpine,
      CORD_TUBE_SEGMENTS,
      CORD_RADIAL_SEGMENTS,
      (t) => {
        // ease NARROWER into the stub (t<0.12) so the cord tucks cleanly into the
        // brainstem bulge instead of ballooning at the seam; uniform thick trunk
        // through the middle; soften to the conus tip (t>0.85). The exact profile
        // the operator liked. CORD_SIGMA_TOP_EASE>1 widens the seam toward the
        // stem girth; we invert it to a <1 narrowing so it slots INSIDE the bulge.
        const topEase = 1.0 / CORD_SIGMA_TOP_EASE; // ~0.85 → slightly narrower at the very top
        if (t < 0.12) return CORD_SIGMA * THREE.MathUtils.lerp(topEase, 1.0, t / 0.12);
        if (t > 0.85) return CORD_SIGMA * THREE.MathUtils.lerp(1.0, 0.6, (t - 0.85) / 0.15);
        return CORD_SIGMA;
      }
    );
    // cord spans body arc 0..0.82 (spray takes 0.82..1) — arc from Y down the cord.
    bakeNerveAttributes(cordGeo, random, (_x, y) => {
      const f = THREE.MathUtils.clamp((CORD_TOP_Y - y) / Math.max(CORD_TOP_Y - CORD_BOTTOM_Y, 1e-4), 0, 1);
      return f * 0.82;
    });

    const cordBundle = mergeGeometries([stemGeo, cordGeo], false);
    stemGeo.dispose();
    cordGeo.dispose();

    // ── 2) VERTEBRAE — stacked centrum rings + discs + processes → merged (1 call) ──
    const vertebraGeos: THREE.BufferGeometry[] = [];
    const pushVertebraGeo = (geo: THREE.BufferGeometry, label: string) => {
      assertNerveAttributeSet(geo, label);
      vertebraGeos.push(geo);
    };
    if (VERTEBRA_RINGS) {
      SEGMENT_ANCHORS.forEach((anchor, i) => {
        const f = SEGMENT_COUNT === 1 ? 0 : i / (SEGMENT_COUNT - 1);
        const segArc = 0.05 + f * 0.7;
        const ringR = THREE.MathUtils.lerp(VERTEBRA_RING_TOP_R, VERTEBRA_RING_BOTTOM_R, f);
        const bodyR = ringR * (1.0 + 0.35 * THREE.MathUtils.smoothstep(f, 0.55, 1.0));
        const vertebraBirth = new THREE.Vector3(anchor.x, anchor.y, anchor.z);
        const stackSpan = (VERTEBRA_GIRTH - 1) * VERTEBRA_GIRTH_SPACING;
        for (let g = 0; g < VERTEBRA_GIRTH; g++) {
          const gy =
            VERTEBRA_GIRTH === 1
              ? anchor.y
              : anchor.y + (g / (VERTEBRA_GIRTH - 1) - 0.5) * stackSpan;
          const torus = new THREE.TorusGeometry(
            bodyR,
            VERTEBRA_RING_TUBE,
            VERTEBRA_RADIAL_SEGMENTS,
            VERTEBRA_TUBULAR_SEGMENTS
          );
          // Lie flat (XZ plane) encircling the vertical cord, then seat on the anchor.
          torus.rotateX(Math.PI / 2);
          torus.translate(anchor.x, gy, anchor.z);
          // GROWTH: the vertebra collapses to its spine anchor, then blooms OUT of
          // the cord as the front reaches its segment — "generated from the spine".
          bakeBirthConstant(torus, vertebraBirth);
          // light, legible jitter only (a touch of organic life, not chaos)
          bakeNerveAttributes(torus, random, () => segArc + (random() - 0.5) * 0.01, 0.04);
          pushVertebraGeo(torus, `vertebra-${i}-centrum-${g}`);
        }

        if (i < SEGMENT_ANCHORS.length - 1) {
          const discY = (anchor.y + SEGMENT_ANCHORS[i + 1].y) * 0.5;
          const disc = new THREE.TorusGeometry(
            bodyR * DISC_R_SCALE,
            DISC_TUBE,
            PROC_RADIAL_SEGMENTS,
            VERTEBRA_TUBULAR_SEGMENTS
          );
          disc.rotateX(Math.PI / 2);
          disc.translate(anchor.x, discY, anchor.z);
          bakeBirthConstant(disc, vertebraBirth);
          bakeNerveAttributes(disc, random, () => segArc + (random() - 0.5) * 0.01, 0.04);
          pushVertebraGeo(disc, `vertebra-${i}-disc`);
        }

        const spLen = THREE.MathUtils.lerp(SPINOUS_LEN_TOP, SPINOUS_LEN_BOT, f);
        const tilt =
          THREE.MathUtils.lerp(0.15, 0.85, THREE.MathUtils.smoothstep(f, 0.15, 0.55)) *
          (1.0 - 0.5 * THREE.MathUtils.smoothstep(f, 0.75, 1.0));
        const p0 = new THREE.Vector3(anchor.x, anchor.y, anchor.z - bodyR * 0.2);
        const p1 = new THREE.Vector3(
          anchor.x,
          anchor.y - spLen * tilt * 0.4,
          anchor.z - bodyR - spLen * 0.45
        );
        const p2 = new THREE.Vector3(
          anchor.x,
          anchor.y - spLen * tilt,
          anchor.z - bodyR - spLen * 0.95
        );
        const spinous = makeTaperedTube(
          [p0, p1, p2],
          PROC_TUBE_SEGMENTS,
          PROC_RADIAL_SEGMENTS,
          (t) => SPINOUS_R * (1.0 - 0.55 * t),
          vertebraBirth
        );
        bakeNerveAttributes(spinous, random, () => segArc + (random() - 0.5) * 0.012, 0.05);
        pushVertebraGeo(spinous, `vertebra-${i}-spinous`);

        const tpLen = THREE.MathUtils.lerp(TRANSVERSE_LEN_TOP, TRANSVERSE_LEN_BOT, f);
        const fwd =
          0.06 *
          THREE.MathUtils.smoothstep(f, 0.2, 0.55) *
          (1.0 - THREE.MathUtils.smoothstep(f, 0.7, 1.0));
        for (const side of [-1, 1] as const) {
          const q0 = new THREE.Vector3(anchor.x, anchor.y, anchor.z);
          const q1 = new THREE.Vector3(
            anchor.x + side * tpLen * 0.5,
            anchor.y + 0.01,
            anchor.z + fwd * 0.5
          );
          const q2 = new THREE.Vector3(
            anchor.x + side * tpLen,
            anchor.y + 0.005,
            anchor.z + fwd
          );
          const transverse = makeTaperedTube(
            [q0, q1, q2],
            PROC_TUBE_SEGMENTS,
            PROC_RADIAL_SEGMENTS,
            (t) => TRANSVERSE_R * (0.7 + 0.5 * t),
            vertebraBirth
          );
          bakeNerveAttributes(
            transverse,
            random,
            () => segArc + (random() - 0.5) * 0.012,
            0.05
          );
          pushVertebraGeo(transverse, `vertebra-${i}-transverse-${side}`);
        }
      });
    }
    const vertebraeBundle =
      vertebraGeos.length > 0 ? mergeGeometries(vertebraGeos, false) : null;
    console.assert(
      vertebraGeos.length === 0 || vertebraeBundle !== null,
      'Vertebrae merge failed; sub-part attributes must match exactly'
    );
    vertebraGeos.forEach((g) => g.dispose());

    // ── 3) BILATERAL NERVE ROOTS — 48 tubes → merged (1 call) ─────────────────
    const rootGeos: THREE.BufferGeometry[] = [];
    SEGMENT_ANCHORS.forEach((anchor, i) => {
      const f = SEGMENT_COUNT === 1 ? 0 : i / (SEGMENT_COUNT - 1);
      const segArc = 0.05 + f * 0.7;
      const len = THREE.MathUtils.lerp(ROOT_LENGTH_TOP, ROOT_LENGTH_GROWTH, f * f); // f*f = accelerating fan
      const outX = THREE.MathUtils.lerp(ROOT_SPREAD_BASE, ROOT_SPREAD_GROWTH, f);
      const droop = THREE.MathUtils.lerp(ROOT_DROOP_TOP, ROOT_DROOP_GROWTH, f);
      const rootR = THREE.MathUtils.lerp(ROOT_RADIUS_TOP, ROOT_RADIUS_BOTTOM, f);

      for (let p = 0; p < ROOT_PAIRS_PER_SEGMENT; p++) {
        const pairBias =
          ROOT_PAIRS_PER_SEGMENT === 1 ? 0 : (p / (ROOT_PAIRS_PER_SEGMENT - 1) - 0.5) * 0.16;
        for (const side of [-1, 1] as const) {
          // Light, seeded organic jitter (legible near-symmetric fan, no chaos) —
          // same math the prior structure used so the SHAPE is preserved.
          const jLen = len * (0.9 + random() * 0.18);
          const jOut = outX * (0.92 + random() * 0.16);
          const jDroop = droop * (0.9 + random() * 0.24);
          const jZmid = (random() - 0.5) * 0.1;
          const jZtip = (random() - 0.5) * 0.18;
          const wander = (random() - 0.5) * 0.07;
          const yJit = (random() - 0.5) * 0.03;
          const rootPath = [
            new THREE.Vector3(anchor.x, anchor.y + pairBias + yJit, anchor.z), // emerge ON the cord
            new THREE.Vector3(
              side * jOut * 0.45 * jLen + wander * 0.3,
              anchor.y - jDroop * 0.25,
              anchor.z + 0.02 + jZmid * 0.5
            ),
            new THREE.Vector3(
              side * jOut * 0.85 * jLen + wander,
              anchor.y - jDroop * 0.62,
              anchor.z - 0.02 + jZmid
            ),
            new THREE.Vector3(
              side * jOut * 1.0 * jLen + wander * 1.3,
              anchor.y - jDroop * (0.97 + random() * 0.12),
              anchor.z + 0.04 + jZtip
            ), // weeping tip
          ];
          const rootGeo = makeTaperedTube(
            rootPath,
            ROOT_TUBE_SEGMENTS,
            ROOT_RADIAL_SEGMENTS,
            (t) => rootR * (0.6 + ROOT_FLARE * t), // flares toward the weeping tip
            rootPath[0].clone() // GROWTH: the root unfurls OUT from its cord attachment
          );
          const rootArc = segArc + (random() - 0.5) * 0.04; // minor hue spread so the fan isn't flat
          bakeNerveAttributes(rootGeo, random, () => rootArc, 0.05);
          rootGeos.push(rootGeo);
        }
      }
    });
    const rootsBundle = rootGeos.length > 0 ? mergeGeometries(rootGeos, false) : null;
    rootGeos.forEach((g) => g.dispose());

    // ── 4) CAUDA-EQUINA SPRAY — 16 tubes → merged (1 call) ────────────────────
    const conus = new THREE.Vector3(0, CORD_BOTTOM_Y, CORD_Z);
    const sprayGeos: THREE.BufferGeometry[] = [];
    for (let s = 0; s < SPRAY_COUNT; s++) {
      const fx = SPRAY_COUNT === 1 ? 0 : (s / (SPRAY_COUNT - 1) - 0.5) * 2; // -1..1 across the fan
      const tipX = fx * SPRAY_FAN_WIDTH + (random() - 0.5) * 0.2;
      const tipZ = CORD_Z + (random() - 0.5) * 0.55;
      const tipY =
        CORD_BOTTOM_Y -
        THREE.MathUtils.lerp(SPRAY_LENGTH_CENTER, SPRAY_LENGTH_EDGE, Math.abs(fx)) +
        (random() - 0.5) * 0.35;
      const sprayPath = [
        conus.clone(),
        new THREE.Vector3(
          fx * 0.15 + (random() - 0.5) * 0.1,
          CORD_BOTTOM_Y - 0.4,
          CORD_Z + 0.02 + (random() - 0.5) * 0.2
        ),
        new THREE.Vector3(
          fx * 0.5 + (random() - 0.5) * 0.16,
          CORD_BOTTOM_Y - 0.9,
          CORD_Z + (random() - 0.5) * 0.32
        ),
        new THREE.Vector3(tipX, tipY, tipZ), // scattered weeping tip
      ];
      const sprayGeo = makeTaperedTube(
        sprayPath,
        SPRAY_TUBE_SEGMENTS,
        SPRAY_RADIAL_SEGMENTS,
        (t) => THREE.MathUtils.lerp(SPRAY_RADIUS_TOP, SPRAY_RADIUS_TIP, t),
        conus.clone() // GROWTH: the spray unfurls OUT from the conus tip (born last)
      );
      // spray spans body arc 0.82..1.0 along its own length (top→tip)
      const yTop = CORD_BOTTOM_Y;
      const yTip = tipY;
      bakeNerveAttributes(
        sprayGeo,
        random,
        (_x, y) => {
          const t = THREE.MathUtils.clamp((yTop - y) / Math.max(yTop - yTip, 1e-4), 0, 1);
          return 0.82 + t * 0.18;
        },
        0.05
      );
      sprayGeos.push(sprayGeo);
    }
    const sprayBundle = sprayGeos.length > 0 ? mergeGeometries(sprayGeos, false) : null;
    sprayGeos.forEach((g) => g.dispose());

    return { cordBundle, vertebraeBundle, rootsBundle, sprayBundle };
  }, []);

  useEffect(() => {
    const { cordBundle, vertebraeBundle, rootsBundle, sprayBundle } = geometries;
    return () => {
      cordBundle?.dispose();
      vertebraeBundle?.dispose();
      rootsBundle?.dispose();
      sprayBundle?.dispose();
    };
  }, [geometries]);

  const { cordBundle, vertebraeBundle, rootsBundle, sprayBundle } = geometries;

  // FOUR draw calls, all wearing the ONE shared nerve material instance →
  // visually one continuous organism with the brain.
  return (
    <group ref={groupRef}>
      {cordBundle && (
        <mesh geometry={cordBundle} material={material} frustumCulled={false} renderOrder={2} />
      )}
      {vertebraeBundle && (
        <mesh geometry={vertebraeBundle} material={material} frustumCulled={false} renderOrder={2} />
      )}
      {rootsBundle && (
        <mesh geometry={rootsBundle} material={material} frustumCulled={false} renderOrder={2} />
      )}
      {sprayBundle && (
        <mesh geometry={sprayBundle} material={material} frustumCulled={false} renderOrder={2} />
      )}
      <VertebraeRepoMapOverlay />
    </group>
  );
}

'use client';

import { useEffect, useMemo, useRef, type MutableRefObject } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import type { CognitiveMode } from '@/components/ui/SuperbrainHUD';
import type { CognitionUniforms } from './SuperbrainScene';
import { createSeededRandom } from '@/lib/seededRandom';

/* -------------------------------------------------------------------------- */
/*  Two-shell fake volume                                                      */
/*                                                                             */
/*  The aura no longer fakes the brain with spheres — both shells reuse the    */
/*  PROCESSED brain geometry (smooth normals + baked region vertex colors)     */
/*  cloned from the cortex, so the volume cues hug the real silhouette:        */
/*                                                                             */
/*    membrane (1.025, BackSide)  — a thin region-tinted atmosphere film just  */
/*                                  outside the cortex; depth-tested against   */
/*                                  the cortex so it survives only as a halo   */
/*                                  hugging the silhouette.                    */
/*    nucleus  (0.85, FrontSide)  — the rose SSS hue glowing brightest at the  */
/*                                  CENTER of the form. Drawn BEFORE the       */
/*                                  cortex (renderOrder -1) so it ghosts       */
/*                                  through the cortex's 0.94 alpha — a        */
/*                                  luminous interior, not a painted skin.     */
/*                                                                             */
/*  Both shells stay below 0.5 output luminance: volume cues, not light        */
/*  sources. Breath/burst arrive through the SHARED CognitionUniforms leaves   */
/*  written once per frame by SuperbrainScene, so the whole organism swells    */
/*  on the same systole. The old fresnel sphere + corona layers are folded     */
/*  into these shells; only the tiny orbiting sparks survive from the old      */
/*  aura.                                                                      */
/* -------------------------------------------------------------------------- */

const TAU = Math.PI * 2;

/** Membrane sits just off the cortex; nucleus glows deep inside it. */
const MEMBRANE_SCALE = 1.025;
const CORE_SCALE = 0.85;

/**
 * Brain-group-local center of the measured GLB bounds — keep in sync with
 * BRAIN_MIN / BRAIN_MAX in SuperbrainScene.tsx. The GLB's origin is OFFSET
 * from the anatomical center, so the shells must scale about this point or
 * the 0.85 nucleus would sag out of the skull.
 */
const BRAIN_CENTER = new THREE.Vector3(0.0015, 0.2055, 0.057);

/** Orbit radius in brain-group-local units (local brain radius ≈ 0.50). */
const SPARK_ORBIT_RADIUS = 0.48;
const SPARK_COUNT = 50;

/* ---------- mode-reactive spark color temperature ---------- */
const AURA_MODE_COLORS: Record<CognitiveMode, THREE.Color> = {
  observe: new THREE.Color('#40e8ff'),      // deep cool cyan — scanning
  synthesize: new THREE.Color('#aef2ff'),   // warmer, whiter — processing heat
  orchestrate: new THREE.Color('#8f7bff'),  // violet-shifted — commanding
};

/** YELLOW-zone amber for the approval hold — accent, never a theme. */
const AURA_HOLD_AMBER = new THREE.Color('#ffb454');


/*  Shell shaders (shared vertex pass — view-space normal + region color)      */
/* -------------------------------------------------------------------------- */

const SHELL_VERTEX_SHADER = /* glsl */ `
  varying vec3 vNormalV;
  varying vec3 vViewDirV;
  varying vec3 vColorV;

  void main() {
    vNormalV = normalize(normalMatrix * normal);
    vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
    vViewDirV = -mvPosition.xyz;
    vColorV = color;
    gl_Position = projectionMatrix * mvPosition;
  }
`;

const MEMBRANE_FRAGMENT_SHADER = /* glsl */ `
  uniform float uBreath;
  uniform float uBurst;
  uniform float uArrival;

  varying vec3 vNormalV;
  varying vec3 vViewDirV;
  varying vec3 vColorV;

  void main() {
    vec3 N = normalize(vNormalV);
    vec3 V = normalize(vViewDirV);

    // BackSide hull: raw normals face AWAY from the camera, so dot(N, V) runs
    // 0 (silhouette) .. -1 (far pole). The lobe brightens just inside the
    // silhouette; the hard 0.25 cap keeps it a film, never a light source.
    float a = pow(max(0.6 - dot(N, V), 0.0), 4.0);
    a = min(a * (0.85 + 0.30 * uBreath + uBurst * 0.45), 0.25);

    // Coalescence reveal: the membrane emerges (alpha 0) as the cortex
    // condenses; full canon strength at rest (uArrival==0 -> *1.0).
    a *= 1.0 - uArrival;

    // Region-tinted atmosphere: additive output peaks at 1.4 * 0.25 = 0.35.
    gl_FragColor = vec4(vColorV * 1.4, a);
  }
`;

const CORE_FRAGMENT_SHADER = /* glsl */ `
  uniform float uBreath;
  uniform float uBurst;
  uniform float uArrival;

  varying vec3 vNormalV;
  varying vec3 vViewDirV;
  varying vec3 vColorV;

  void main() {
    vec3 N = normalize(vNormalV);
    vec3 V = normalize(vViewDirV);

    // Inverse fresnel: brightest at the CENTER of the form — a nucleus
    // ghosting through the dark cortex, the opposite falloff of a rim glow.
    float facing = pow(clamp(dot(N, V), 0.0, 1.0), 2.0);
    float a = min(facing * (0.70 + 0.45 * uBreath + uBurst * 0.50), 1.0);

    // Coalescence reveal: the nucleus interior glow emerges as the cortex
    // condenses; full canon strength at rest (uArrival==0 -> *1.0).
    a *= 1.0 - uArrival;

    // The cortex SSS rose hue with a regional whisper, held at ~0.4 luminance
    // so the nucleus reads as interior light, never bloom.
    vec3 hue = mix(vec3(1.0, 0.25, 0.45), vColorV, 0.12);
    gl_FragColor = vec4(hue * 0.4, a);
  }
`;

/* -------------------------------------------------------------------------- */
/*  Synaptic sparks — tiny motes orbiting the cortex on great circles          */
/* -------------------------------------------------------------------------- */

interface SparkData {
  positions: Float32Array;
  axisX: Float32Array;
  axisY: Float32Array;
  axisZ: Float32Array;
  phases: Float32Array;
  speeds: Float32Array;
  tints: Float32Array;
}

function createSparkData(): SparkData {
  const random = createSeededRandom(0x4e455552);
  const positions = new Float32Array(SPARK_COUNT * 3);
  const axisX = new Float32Array(SPARK_COUNT);
  const axisY = new Float32Array(SPARK_COUNT);
  const axisZ = new Float32Array(SPARK_COUNT);
  const phases = new Float32Array(SPARK_COUNT);
  const speeds = new Float32Array(SPARK_COUNT);
  const tints = new Float32Array(SPARK_COUNT);

  for (let i = 0; i < SPARK_COUNT; i++) {
    // Random orbital axis (unit vector on sphere)
    const theta = random() * TAU;
    const phi = Math.acos(2 * random() - 1);
    axisX[i] = Math.sin(phi) * Math.cos(theta);
    axisY[i] = Math.sin(phi) * Math.sin(theta);
    axisZ[i] = Math.cos(phi);

    phases[i] = random() * TAU;
    speeds[i] = 0.4 + random() * 0.6;
    // 0 = mode color, 1 = pale star tint
    tints[i] = random() < 0.65 ? 0.0 : 1.0;
  }

  return { positions, axisX, axisY, axisZ, phases, speeds, tints };
}

const SPARK_VERTEX_SHADER = /* glsl */ `
  uniform float uTime;
  uniform float uActivity;
  uniform vec3 uColor;

  attribute float aAxisX;
  attribute float aAxisY;
  attribute float aAxisZ;
  attribute float aPhase;
  attribute float aSpeed;
  attribute float aTint;

  varying vec3 vColor;
  varying float vAlpha;

  void main() {
    // Build great-circle orbit: two orthonormal vectors perpendicular to the axis.
    vec3 axis = normalize(vec3(aAxisX, aAxisY, aAxisZ));
    // Choose an arbitrary "up" that isn't parallel to axis
    vec3 up = abs(axis.y) < 0.99 ? vec3(0.0, 1.0, 0.0) : vec3(1.0, 0.0, 0.0);
    vec3 tangent = normalize(cross(axis, up));
    vec3 bitangent = cross(axis, tangent);

    float angle = aPhase + uTime * aSpeed;
    float r = ${SPARK_ORBIT_RADIUS.toFixed(4)};
    vec3 transformed = (cos(angle) * tangent + sin(angle) * bitangent) * r;

    vec4 mvPosition = modelViewMatrix * vec4(transformed, 1.0);
    float distanceScale = 46.0 / max(8.0, -mvPosition.z);
    gl_PointSize = clamp((1.0 + aTint * 0.5) * distanceScale * (0.8 + uActivity * 0.4), 0.8, 2.8);
    gl_Position = projectionMatrix * mvPosition;

    // Flicker — per-spark phase offsets, never a body-wide pulse.
    float flicker = 0.7 + 0.3 * sin(uTime * 3.8 + aPhase * 11.0);

    // Pale star tint, never pure white (ACES clips white to paper).
    vec3 star = vec3(0.82, 0.88, 1.0);
    vColor = mix(uColor, star, aTint) * (1.2 + uActivity * 0.6);
    vAlpha = (0.45 + uActivity * 0.45) * flicker;
  }
`;

const SPARK_FRAGMENT_SHADER = /* glsl */ `
  varying vec3 vColor;
  varying float vAlpha;

  void main() {
    float radius = length(gl_PointCoord - vec2(0.5));
    if (radius > 0.5) discard;
    float core = 1.0 - smoothstep(0.0, 0.5, radius);
    gl_FragColor = vec4(vColor * (0.7 + core * 0.6), vAlpha * core);
  }
`;

/* -------------------------------------------------------------------------- */
/*  Component                                                                  */
/* -------------------------------------------------------------------------- */

export default function NeuralAura({
  activity,
  mode,
  source,
  uniforms,
  shells: shellBudget = 2,
  arrival,
}: {
  activity: number;
  mode: CognitiveMode;
  /** Processed brain clone (smooth normals + baked region vertex colors). */
  source: THREE.Object3D;
  uniforms: CognitionUniforms;
  /** Shell budget (quality tier): 2 = membrane + nucleus, 1 = membrane only. */
  shells?: 1 | 2;
  /** Shared coalescence scalar: 1 = arriving (shells faded out), 0 = settled. */
  arrival?: MutableRefObject<number>;
}) {
  const sparkMaterialRef = useRef<THREE.ShaderMaterial>(null);
  const smoothedActivityRef = useRef(THREE.MathUtils.clamp(activity, 0, 1));
  // One shared arrival leaf for both shell materials — written once per frame.
  const arrivalUniformRef = useRef({ value: 0 });

  const sparkData = useMemo(() => createSparkData(), []);

  const auraColor = useMemo(() => AURA_MODE_COLORS.observe.clone(), []);

  const sparkUniforms = useMemo(
    () => ({
      // Shared time leaf — sparks orbit on the same clock as the cortex.
      uTime: uniforms.uTime,
      uActivity: { value: 0 },
      uColor: { value: auraColor },
    }),
    [auraColor, uniforms],
  );

  // Both shells clone(true) the processed brain — the clones SHARE the baked
  // geometry (color attribute + smooth normals), so the shells read the same
  // region map as the cortex for free. Only the materials are replaced.
  const shells = useMemo(() => {
    const membraneMaterial = new THREE.ShaderMaterial({
      uniforms: { uBreath: uniforms.uBreath, uBurst: uniforms.uBurst, uArrival: arrivalUniformRef.current },
      vertexShader: SHELL_VERTEX_SHADER,
      fragmentShader: MEMBRANE_FRAGMENT_SHADER,
      vertexColors: true,
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      side: THREE.BackSide,
      toneMapped: false,
    });
    const coreMaterial = new THREE.ShaderMaterial({
      uniforms: { uBreath: uniforms.uBreath, uBurst: uniforms.uBurst, uArrival: arrivalUniformRef.current },
      vertexShader: SHELL_VERTEX_SHADER,
      fragmentShader: CORE_FRAGMENT_SHADER,
      vertexColors: true,
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      depthTest: true,
      side: THREE.FrontSide,
      toneMapped: false,
    });

    const dress = (root: THREE.Object3D, material: THREE.Material, renderOrder: number) => {
      root.traverse((object) => {
        if (!(object instanceof THREE.Mesh)) return;
        object.material = material;
        object.renderOrder = renderOrder;
      });
      return root;
    };

    return {
      // Membrane AFTER the cortex (renderOrder 1): depth-tested down to a
      // silhouette halo. Nucleus BEFORE the cortex (renderOrder -1): the
      // cortex's 0.94-alpha blend lets the interior glow ghost through.
      membrane: dress(source.clone(true), membraneMaterial, 1),
      core: dress(source.clone(true), coreMaterial, -1),
      membraneMaterial,
      coreMaterial,
    };
  }, [source, uniforms]);

  useEffect(
    () => () => {
      // Geometry is shared with the cortex — dispose only our materials.
      shells.membraneMaterial.dispose();
      shells.coreMaterial.dispose();
    },
    [shells],
  );

  const sparkGeometry = useMemo(() => {
    const geom = new THREE.BufferGeometry();
    geom.setAttribute('position', new THREE.BufferAttribute(sparkData.positions, 3));
    geom.setAttribute('aAxisX', new THREE.BufferAttribute(sparkData.axisX, 1));
    geom.setAttribute('aAxisY', new THREE.BufferAttribute(sparkData.axisY, 1));
    geom.setAttribute('aAxisZ', new THREE.BufferAttribute(sparkData.axisZ, 1));
    geom.setAttribute('aPhase', new THREE.BufferAttribute(sparkData.phases, 1));
    geom.setAttribute('aSpeed', new THREE.BufferAttribute(sparkData.speeds, 1));
    geom.setAttribute('aTint', new THREE.BufferAttribute(sparkData.tints, 1));
    return geom;
  }, [sparkData]);

  useEffect(() => {
    return () => {
      sparkGeometry.dispose();
    };
  }, [sparkGeometry]);

  useFrame((state, delta) => {
    smoothedActivityRef.current = THREE.MathUtils.damp(
      smoothedActivityRef.current,
      THREE.MathUtils.clamp(activity, 0, 1),
      4,
      delta,
    );

    const energyState = 
      (smoothedActivityRef.current > 0.7) ? 'feast' :
      (smoothedActivityRef.current < 0.2) ? 'hibernation' : 'conservation';
      
    const ENERGY_COLORS = {
      hibernation: new THREE.Color('#10164a'), // deep dark blue
      conservation: new THREE.Color('#8f7bff'), // violet
      feast: new THREE.Color('#ffb454'), // bright amber
    };

    const targetColor = ENERGY_COLORS[energyState];
    auraColor.lerp(targetColor, Math.min(1, delta * 2.5));
    // Approval hold: the atmosphere itself defers to YELLOW-zone amber.
    const holding = uniforms.uHold.value;
    if (holding > 0.01) {
      auraColor.lerp(AURA_HOLD_AMBER, Math.min(1, delta * 2.5) * holding);
    }

    if (sparkMaterialRef.current) {
      sparkMaterialRef.current.uniforms.uActivity.value = smoothedActivityRef.current;
    }

    // Coalescence reveal for the shells (membrane + nucleus). One write feeds
    // both materials via the shared leaf; 0 at rest keeps canon strength.
    arrivalUniformRef.current.value = arrival?.current ?? 0;
  });

  // Wrapper groups scale each shell about the measured brain CENTER (not the
  // offset GLB origin): position = center * (1 - s) compensates the shift.
  return (
    <group>
      {/* Shell 1 — membrane: region-tinted atmosphere just off the cortex */}
      <group
        position={[
          BRAIN_CENTER.x * (1 - MEMBRANE_SCALE),
          BRAIN_CENTER.y * (1 - MEMBRANE_SCALE),
          BRAIN_CENTER.z * (1 - MEMBRANE_SCALE),
        ]}
        scale={MEMBRANE_SCALE}
      >
        <primitive object={shells.membrane} />
      </group>

      {/* Shell 2 — nucleus: rose interior glow ghosting through the cortex.
          First shell dropped under a reduced tier budget (full-mesh overdraw). */}
      {shellBudget >= 2 && (
        <group
          position={[
            BRAIN_CENTER.x * (1 - CORE_SCALE),
            BRAIN_CENTER.y * (1 - CORE_SCALE),
            BRAIN_CENTER.z * (1 - CORE_SCALE),
          ]}
          scale={CORE_SCALE}
        >
          <primitive object={shells.core} />
        </group>
      )}

      {/* Synaptic sparks — tiny orbiting motes (the survivors of the old aura) */}
      <points geometry={sparkGeometry} frustumCulled={false}>
        <shaderMaterial
          ref={sparkMaterialRef}
          vertexShader={SPARK_VERTEX_SHADER}
          fragmentShader={SPARK_FRAGMENT_SHADER}
          uniforms={sparkUniforms}
          transparent
          depthWrite={false}
          blending={THREE.AdditiveBlending}
          toneMapped={false}
        />
      </points>
    </group>
  );
}

/**
 * NodeLattice — the supercomputer node-lattice inside the brain shape.
 *
 * These tests pin the DATA-TRUE topology contract (the operator's two
 * non-negotiables): the hubs ARE the real anatomical work-anchors, and the
 * intra-region edges keep each lobe a distinct cluster. The WebGL rendering is
 * deliberately NOT tested here (no GL context in vitest); the topology is a
 * pure function so the invariants can be locked without a renderer.
 */
import { describe, expect, it } from 'vitest';

import {
  buildLatticeData,
  HUBS,
  SATELLITES_PER_HUB,
  EDGE_K,
  hubKeyForTool,
  hubIndexForEvent,
} from './NodeLattice';
import type { QualityTier } from '@/components/QualityTierProvider';

const TIERS: QualityTier[] = ['high', 'medium', 'low'];
const idx = (key: string) => HUBS.findIndex((h) => h.key === key);

describe('NodeLattice hubs (DATA-TRUE anchors)', () => {
  it('are the 4 REAL anatomical anchors + 1 clearly-authored ROUTER', () => {
    expect(HUBS.map((h) => h.key)).toEqual(['CAUSAL', 'ARCHIVE', 'LATTICE', 'SIGNAL', 'ROUTER']);
    // Only the authored central node is flagged authored; the 4 anchors are real.
    expect(HUBS.filter((h) => h.authored).map((h) => h.key)).toEqual(['ROUTER']);
  });

  it('the 4 anchor positions match SuperbrainScene WAVE_REGION_ANCHORS verbatim', () => {
    expect(HUBS[0].pos.toArray()).toEqual([0.0, 0.26, 0.48]); // CAUSAL — frontal
    expect(HUBS[1].pos.toArray()).toEqual([0.34, 0.16, 0.11]); // ARCHIVE — temporal
    expect(HUBS[2].pos.toArray()).toEqual([0.0, 0.61, 0.11]); // LATTICE — parietal crown
    expect(HUBS[3].pos.toArray()).toEqual([0.05, 0.31, -0.38]); // SIGNAL — occipital
  });
});

describe('NodeLattice topology', () => {
  it('node count is tier-budgeted (1 hub + N satellites per lobe)', () => {
    for (const tier of TIERS) {
      const { nodes } = buildLatticeData(tier);
      expect(nodes).toHaveLength(HUBS.length + HUBS.length * SATELLITES_PER_HUB[tier]);
      expect(nodes.filter((n) => n.isHub)).toHaveLength(HUBS.length);
    }
  });

  it('is deterministic (seeded) — identical positions across builds', () => {
    const a = buildLatticeData('high');
    const b = buildLatticeData('high');
    expect(a.nodes.map((n) => n.pos.toArray())).toEqual(b.nodes.map((n) => n.pos.toArray()));
  });

  it('coalescence igniteDelay is deterministic, in 0..1, and lowest at the ROUTER core', () => {
    const a = buildLatticeData('high');
    const b = buildLatticeData('high');
    expect(a.nodes.map((n) => n.igniteDelay)).toEqual(b.nodes.map((n) => n.igniteDelay));
    for (const n of a.nodes) {
      expect(n.igniteDelay).toBeGreaterThanOrEqual(0);
      expect(n.igniteDelay).toBeLessThanOrEqual(1);
    }
    // The authored ROUTER hub sits at BRAIN_CENTER → it ignites first (delay ~0).
    const routerHub = a.nodes.find((n) => n.isHub && n.hub === idx('ROUTER'))!;
    expect(routerHub.igniteDelay).toBeCloseTo(0, 5);
    // Some lobe node ignites meaningfully later (the wave reaches outward).
    expect(Math.max(...a.nodes.map((n) => n.igniteDelay))).toBeGreaterThan(0.3);
  });

  it('edges are STRICTLY intra-region (both endpoints in the same lobe)', () => {
    for (const tier of TIERS) {
      const { nodes, edges } = buildLatticeData(tier);
      // endpoints are shared position refs with the owning nodes.
      const hubOf = (p: unknown) => nodes.find((n) => n.pos === p)?.hub;
      for (const e of edges) {
        const ha = hubOf(e.a);
        const hb = hubOf(e.b);
        expect(ha).toBeTypeOf('number');
        expect(ha).toBe(hb);
      }
    }
  });

  it('low tier drops intra-cluster knn — every edge is a hub spoke', () => {
    expect(EDGE_K.low).toBe(0);
    const { nodes, edges } = buildLatticeData('low');
    const hubPos = new Set(nodes.filter((n) => n.isHub).map((n) => n.pos));
    for (const e of edges) {
      expect(hubPos.has(e.a) || hubPos.has(e.b)).toBe(true);
    }
  });

  it('high tier adds intra-cluster links beyond the spokes', () => {
    const { nodes, edges } = buildLatticeData('high');
    const spokeCount = HUBS.length * SATELLITES_PER_HUB.high; // one spoke per satellite
    expect(edges.length).toBeGreaterThan(spokeCount);
  });
});

describe('NodeLattice P2 firing map (DATA-TRUE event -> hub)', () => {
  it('routes tools to the same lobe the cortex uses (waveLabelForTool parity)', () => {
    expect(hubKeyForTool('plan')).toBe('CAUSAL');
    expect(hubKeyForTool('recall_memory')).toBe('CAUSAL');
    expect(hubKeyForTool('read_file')).toBe('ARCHIVE');
    expect(hubKeyForTool('create_file')).toBe('LATTICE');
    expect(hubKeyForTool('verify')).toBe('LATTICE');
    expect(hubKeyForTool('something_unknown')).toBe('SIGNAL');
  });

  it('fires a real tool-engaged dispatch at its owning hub', () => {
    expect(hubIndexForEvent({ type: 'agent-dispatch', detail: 'tool engaged: read_file' })).toBe(idx('ARCHIVE'));
    expect(hubIndexForEvent({ type: 'agent-dispatch', detail: 'tool engaged: edit_file' })).toBe(idx('LATTICE'));
    expect(hubIndexForEvent({ type: 'agent-dispatch', detail: 'PLANNER caste online' })).toBe(idx('CAUSAL'));
  });

  it('maps verification + recall + route to the right hubs', () => {
    expect(hubIndexForEvent({ type: 'knowledge-acquired', label: 'VERIFICATION GREEN' })).toBe(idx('LATTICE'));
    expect(hubIndexForEvent({ type: 'knowledge-acquired', detail: 'trail #12 reinforced — strength 0.7' })).toBe(idx('CAUSAL'));
    expect(hubIndexForEvent({ type: 'route', label: 'OLLAMA' })).toBe(idx('ROUTER'));
  });

  it('directive/synthesis/burst pulse ALL hubs (-1); ignored events return null', () => {
    expect(hubIndexForEvent({ type: 'directive' })).toBe(-1);
    expect(hubIndexForEvent({ type: 'synthesis' })).toBe(-1);
    expect(hubIndexForEvent({ type: 'approval-required' })).toBeNull();
    expect(hubIndexForEvent({ type: 'telemetry' })).toBeNull();
    expect(hubIndexForEvent({ type: 'voice-speaking' })).toBeNull();
  });
});

'use client';

/* -------------------------------------------------------------------------- */
/*  NodeLattice — the supercomputer NEUROLOGY inside the brain shape           */
/*                                                                            */
/*  Operator's vision: the cherished brain GLB *silhouette stays*; the         */
/*  INTERIOR becomes a living lattice of glowing, colorful COMPUTE NODES wired */
/*  together (a real topology), with signals firing node→node in the SAME     */
/*  fiber-optic packet language as the external NervousSystem bus. It is       */
/*  DATA-TRUE: the hubs are the four REAL anatomical work-anchors the engine   */
/*  already routes tools to (waveLabelForTool: CAUSAL/ARCHIVE/LATTICE/SIGNAL), */
/*  plus one clearly-authored central ROUTER/SECURITY bus node.                */
/*                                                                            */
/*  Build is PHASED (see .aios/state/NODE_BRAIN_RESEARCH.md). THIS is PHASE 1: */
/*  the STATIC lattice — prove the shape, glow, and distinct-from-tissue read  */
/*  in the operator's browser BEFORE deeper data wiring. P2 binds cognition-   */
/*  bus events to per-node firing (the activation path is live here); P3       */
/*  renders live skill-trail nodes; P4 adds the real backend graph-traversal   */
/*  capability. Nothing here publishes or mutates the bus — it is (and stays)  */
/*  a pure consumer of the shared SCENE_UNIFORMS.                              */
/*                                                                            */
/*  THREE draw calls only: 1 InstancedMesh (nodes) + 1 merged TubeGeometry     */
/*  (intra-region edges) + 1 merged TubeGeometry (the cross-region backbone    */
/*  bus). Energy-not-matter identity throughout: near-black carrier + additive */
/*  + depthWrite:false, exactly like the cortex filaments, NeuralAura and the  */
/*  fiber-optic bus — so it ADDS light to the cortex rather than occluding it. */
/*                                                                            */
/*  The DATA-TRUE topology is a PURE function (buildLatticeData) so it can be  */
/*  unit-tested independent of WebGL; the component only turns that data into  */
/*  THREE objects. FIDELITY: additive, his GLB/textures untouched, the canon   */
/*  cortex silhouette is preserved. Mounted by SuperbrainScene's BrainModel    */
/*  ONLY when `NODE_BRAIN === true`; flip that const off to restore the canon  */
/*  organ path byte-for-byte. Final call: HIS eyes.                            */
/*                                                                            */
/*  THE LAW (opening-motion + a11y):                                          */
/*   • uArrival drives a 3-beat COALESCENCE — nodes ignite ROUTER→outward,     */
/*     edges wipe in along their cables, first packets fire as breath settles. */
/*   • uReducedMotion freezes packet travel + snaps coalescence to assembled   */
/*     (still a lit, wired graph — just no motion).                           */
/*   • uBreath/uHold/uBurst ride for free from SCENE_UNIFORMS.                 */
/* -------------------------------------------------------------------------- */

import { useEffect, useMemo, useRef, useState } from 'react';
import * as THREE from 'three';
import { useFrame } from '@react-three/fiber';
import { mergeGeometries } from 'three/examples/jsm/utils/BufferGeometryUtils.js';
import { createSeededRandom } from '@/lib/seededRandom';
import { subscribeCognition } from '@/lib/cognitionBus';
import { fetchFactGraph, getKnownTrails } from '@/lib/aiosAdapter';
import type { FactEdge, TrailRow } from '@/lib/aiosAdapter';
import type { CognitionUniforms } from './SuperbrainScene';
import type { QualityTier } from '@/components/QualityTierProvider';

const TAU = Math.PI * 2;

/* ---------------------------------------------------------------------------
 * Brain-group-local bounds of /models/brain.glb (root scale 0.01) — IDENTICAL
 * to the constants in SuperbrainScene. Nodes live in this same space (the
 * lattice mounts as a child of the BrainModel group, so the group's
 * BRAIN_SCALE/rotation/drift carry it for free — like CorticalSignals).
 * ------------------------------------------------------------------------- */
const BRAIN_MIN = new THREE.Vector3(-0.379, -0.222, -0.439);
const BRAIN_MAX = new THREE.Vector3(0.382, 0.633, 0.553);
const BRAIN_CENTER = new THREE.Vector3().addVectors(BRAIN_MIN, BRAIN_MAX).multiplyScalar(0.5);
/** Risk R1 (clipping through the non-box mesh): keep placement 15% inward of
 *  the bounding box for Phase 1. A three-mesh-bvh inside-test is a later phase
 *  IF the operator sees leaks — the inward margin is the cheap honest first move. */
const INWARD = 0.85;

/* ---------------------------------------------------------------------------
 * THE HUBS — 4 REAL anatomical anchors (verbatim from SuperbrainScene's
 * WAVE_REGION_ANCHORS, ANTERIOR_SIGN=+1) + 1 AUTHORED central bus node.
 * Colors are the brain's own baked region palette, so the lattice reads as the
 * same organism. (Research correction #1: there is NO 5th data anchor — the
 * ROUTER node is a deliberately authored interior position, NOT a real anchor.)
 * ------------------------------------------------------------------------- */
export interface Hub {
  key: string;
  /** brain-group-local position */
  pos: THREE.Vector3;
  color: string;
  /** the work this lobe owns (waveLabelForTool routing), for P2 wiring */
  routes: string;
  authored?: boolean;
}

export const HUBS: Hub[] = [
  { key: 'CAUSAL', pos: new THREE.Vector3(0.0, 0.26, 0.48), color: '#ff3b28', routes: 'plan/skill/recall/memory' }, // frontal
  { key: 'ARCHIVE', pos: new THREE.Vector3(0.34, 0.16, 0.11), color: '#36f07a', routes: 'read/search/list/web/fetch' }, // temporal
  { key: 'LATTICE', pos: new THREE.Vector3(0.0, 0.61, 0.11), color: '#19d4f0', routes: 'create/edit/write/exec/verify' }, // parietal crown
  { key: 'SIGNAL', pos: new THREE.Vector3(0.05, 0.31, -0.38), color: '#9b3bff', routes: 'signal/route/security' }, // occipital
  // AUTHORED (not a data anchor): the central compute/router bus the four lobes feed.
  { key: 'ROUTER', pos: BRAIN_CENTER.clone(), color: '#6a35ff', routes: 'router/provider/security spine', authored: true },
];

/* ---------------------------------------------------------------------------
 * TUNABLES — the operator's dials. Every visual knob lives here so the look
 * can be retuned without hunting through shader strings. The brightness levers
 * below (NODE_GAIN / *_CARRIER_GAIN / SIGNAL_GAIN) are also live-tunable at
 * runtime via window.__NODELATTICE (dev-only) — dial in the real browser, then
 * report the values to bake here as the new defaults.
 * ------------------------------------------------------------------------- */
/** Tier budget — conservative for a 16GB box (matches NODE_BRAIN_RESEARCH).
 *  Total NODE_COUNT = (HUBS.length) + (HUBS.length × satellites). */
export const SATELLITES_PER_HUB: Record<QualityTier, number> = { high: 24, medium: 16, low: 3 };
/** EDGE topology density: k-nearest INTRA-cluster links per satellite
 *  (cross-region links are backbone-only — R2). 0 = spokes only. */
export const EDGE_K: Record<QualityTier, number> = { high: 3, medium: 2, low: 0 };

/** NODE_SIZE — energy-sphere radii (brain-group-local units). */
const HUB_RADIUS = 0.05;
const SAT_RADIUS = 0.03;
/** EDGE_MAX_DIST proxy: satellite scatter radius around each hub. Clusters stay
 *  distinct (R2); intra-cluster k-NN only ever links within this sphere. */
const LOBE_RADIUS = 0.11;
/** GLOW levers (idle brightness; firing/burst push past the bloom knee). */
const NODE_GAIN = 1.1; // node brightness — pushed past the PostFX bloom knee so the
                       // memory nodes POP/bloom through the translucent cortex during reveal
const EDGE_CARRIER_GAIN = 4.0; // lobe-wire always-visible (dial down if too web-like)
const BACKBONE_CARRIER_GAIN = 4.5; // major bus slightly brighter than lobe edges
const SIGNAL_GAIN = 3.0; // packet peak luma >> 1 so glitters cross the bloom knee
/** FLOW_SPEED — packet travel multipliers (per-edge speed jitter on top). */
const EDGE_TUBE_RADIUS = 0.0034;
const BACKBONE_TUBE_RADIUS = 0.005;

/** Map a tool name to the hub whose lobe owns that kind of work — MIRRORS
 *  SuperbrainScene.waveLabelForTool so the lattice and the cortex agree on
 *  which region a given tool lights. */
export function hubKeyForTool(tool: string): string {
  const t = tool.toLowerCase();
  if (/plan|orchestr|skill|recall|memory|lesson/.test(t)) return 'CAUSAL';
  if (/read|search|list|web|fetch|grep|inspect/.test(t)) return 'ARCHIVE';
  if (/create|edit|write|exec|verify|run|build/.test(t)) return 'LATTICE';
  return 'SIGNAL';
}

/** Which hub a REAL cognition-bus event should fire: a HUBS index, -1 for ALL
 *  hubs (a whole-organism pulse), or null for events the lattice ignores.
 *  DATA-TRUE — keyed off the real bus events + the engine's own tool->lobe
 *  routing (see WORKING_BRAIN_CANON_RESEARCH §1.2). The lattice is a pure
 *  SUBSCRIBER: it never publishes and never adds bus types. */
export function hubIndexForEvent(event: { type: string; label?: string; detail?: string }): number | null {
  const idx = (key: string) => HUBS.findIndex((h) => h.key === key);
  const label = event.label ?? '';
  const detail = event.detail ?? '';
  switch (event.type) {
    case 'route':
      return idx('ROUTER');
    case 'directive':
    case 'synthesis':
    case 'burst':
      return -1; // whole-organism pulse
    case 'agent-dispatch': {
      const m = detail.match(/tool engaged: (.+)/);
      if (m) return idx(hubKeyForTool(m[1]));
      if (/caste online/i.test(detail) || /INTENT|TRAIL WEAKENED/i.test(label)) return idx('CAUSAL');
      return idx('SIGNAL');
    }
    case 'knowledge-acquired': {
      if (/VERIFICATION/i.test(label)) return idx('LATTICE');
      if (/SKILL MASTERED|CAPABILITY EARNED|AUTONOMOUS/i.test(label) || /trail #/i.test(detail)) return idx('CAUSAL');
      if (/SIGNAL|TITAN/i.test(label)) return idx('SIGNAL');
      if (/ARCHIVE|MYTHOS|MEMORY/i.test(label)) return idx('ARCHIVE');
      if (/CAUSAL|GRAPH|DELTA/i.test(label)) return idx('CAUSAL');
      if (/SEMANTIC|LATTICE/i.test(label)) return idx('LATTICE');
      return idx('ARCHIVE'); // generic knowledge intake -> the archive lobe
    }
    default:
      return null; // approval-required/-resolved (uHold handles), telemetry, voice-speaking
  }
}

/* ---------------------------------------------------------------------------
 * PURE DATA MODEL (no THREE rendering) — unit-testable. The component below
 * turns this into InstancedMesh / merged TubeGeometry edges + backbone.
 * ------------------------------------------------------------------------- */
export interface LatticeNode {
  pos: THREE.Vector3;
  color: THREE.Color;
  radius: number;
  /** index into HUBS this node belongs to */
  hub: number;
  isHub: boolean;
  /** 0..1 normalized distance from BRAIN_CENTER — the COALESCENCE ignite delay
   *  (ROUTER core lights first, the four lobes bloom outward). Baked once. */
  igniteDelay: number;
}
export interface LatticeEdge {
  /** endpoint position refs (shared with the owning nodes) */
  a: THREE.Vector3;
  b: THREE.Vector3;
  color: THREE.Color;
  phase: number;
  speed: number;
}
export interface LatticeData {
  nodes: LatticeNode[];
  edges: LatticeEdge[];
}

/** Uniform direction on the unit sphere from a seeded PRNG. */
function randomUnit(rng: () => number): THREE.Vector3 {
  const u = rng() * 2 - 1;
  const t = rng() * TAU;
  const s = Math.sqrt(Math.max(0, 1 - u * u));
  return new THREE.Vector3(s * Math.cos(t), s * Math.sin(t), u);
}

/** Clamp a point to 15% inside the brain bounding box (R1). */
function clampInward(p: THREE.Vector3): void {
  const lo = new THREE.Vector3().lerpVectors(BRAIN_CENTER, BRAIN_MIN, INWARD);
  const hi = new THREE.Vector3().lerpVectors(BRAIN_CENTER, BRAIN_MAX, INWARD);
  p.x = THREE.MathUtils.clamp(p.x, lo.x, hi.x);
  p.y = THREE.MathUtils.clamp(p.y, lo.y, hi.y);
  p.z = THREE.MathUtils.clamp(p.z, lo.z, hi.z);
}

/** Largest center→corner distance of the inward-clamped box. Normalizes the
 *  per-node ignite delay into 0..1 so coalescence is resolution-independent. */
const MAX_CENTER_DIST = (() => {
  const lo = new THREE.Vector3().lerpVectors(BRAIN_CENTER, BRAIN_MIN, INWARD);
  const hi = new THREE.Vector3().lerpVectors(BRAIN_CENTER, BRAIN_MAX, INWARD);
  return Math.max(BRAIN_CENTER.distanceTo(lo), BRAIN_CENTER.distanceTo(hi));
})();

/** Max real nodes before we cap (prevents InstancedMesh explosion on big graphs). */
const MAX_REAL_NODES = 160;

/** Deterministic integer hash of a string — used to assign entities to hubs
 *  and to seed per-entity positional jitter. Stable across reloads. */
function strHash(s: string): number {
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return h;
}

/** Real-data input for buildLatticeData. Both fields are optional; whichever
 *  is non-empty first wins (graph > trails > synthetic). */
export interface RealLatticeData {
  graphEdges?: FactEdge[];
  trails?: TrailRow[];
}

/**
 * Build the DATA-TRUE lattice topology. Deterministic (seeded) so mounts and
 * screenshot baselines stay identical.
 *
 * Priority: real.graphEdges → real.trails → synthetic fallback.
 * Edges are STRICTLY intra-region (each lobe is a distinct cluster) in the
 * synthetic path; cross-region connection is the backbone only.
 */
export function buildLatticeData(tier: QualityTier, real?: RealLatticeData): LatticeData {
  // House rule: never unseeded randomness.
  const random = createSeededRandom(0x4e4f4445); // "NODE"

  const igniteDelayFor = (p: THREE.Vector3) =>
    THREE.MathUtils.clamp(BRAIN_CENTER.distanceTo(p) / MAX_CENTER_DIST, 0, 1);

  /* ================================================================
   * BRANCH A — knowledge-graph edges (subject → predicate → object)
   * ============================================================== */
  if (real?.graphEdges && real.graphEdges.length > 0) {
    // Collect unique entity strings (subjects + objects).
    const entitySet = new Set<string>();
    for (const e of real.graphEdges) {
      entitySet.add(e.subject);
      entitySet.add(e.object);
    }
    // Cap: prefer shallowest entities (depth 1 before depth 2, etc.).
    // We use a stable sort keyed on the min depth the entity appears at.
    const depthOf = new Map<string, number>();
    for (const e of real.graphEdges) {
      depthOf.set(e.subject, Math.min(depthOf.get(e.subject) ?? 99, e.depth));
      depthOf.set(e.object, Math.min(depthOf.get(e.object) ?? 99, e.depth));
    }
    let entities = Array.from(entitySet).sort(
      (a, b) => (depthOf.get(a) ?? 0) - (depthOf.get(b) ?? 0),
    );
    if (entities.length > MAX_REAL_NODES) entities = entities.slice(0, MAX_REAL_NODES);

    // Build one LatticeNode per entity.
    const posMap = new Map<string, THREE.Vector3>();
    const nodes: LatticeNode[] = [];
    for (const entity of entities) {
      const h = strHash(entity);
      const hi = h % HUBS.length;
      const hub = HUBS[hi];
      // Seeded offset inside LOBE_RADIUS so positions are stable across re-renders.
      const rng = createSeededRandom(h);
      const dir = randomUnit(rng);
      const r = LOBE_RADIUS * Math.cbrt(rng());
      const pos = hub.pos.clone().addScaledVector(dir, r);
      clampInward(pos);
      posMap.set(entity, pos);
      const depth = depthOf.get(entity) ?? 1;
      nodes.push({
        pos,
        color: new THREE.Color(hub.color),
        radius: SAT_RADIUS,
        hub: hi,
        isHub: false,
        igniteDelay: THREE.MathUtils.clamp(depth / 3, 0, 1),
      });
    }

    // Build one LatticeEdge per fact (subject→object pair in entity set).
    const edgeRng = createSeededRandom(0x46415445); // "FATE"
    const edges: LatticeEdge[] = [];
    const entityInSet = new Set(entities);
    for (const e of real.graphEdges) {
      if (!entityInSet.has(e.subject) || !entityInSet.has(e.object)) continue;
      const a = posMap.get(e.subject)!;
      const b = posMap.get(e.object)!;
      const hi = strHash(e.subject) % HUBS.length;
      const color = new THREE.Color(HUBS[hi].color).multiplyScalar(0.85);
      edges.push({ a, b, color, phase: edgeRng() * TAU, speed: 0.5 + edgeRng() * 1.5 });
    }
    return { nodes, edges };
  }

  /* ================================================================
   * BRANCH B — live skill-trail nodes (pheromone map)
   * ============================================================== */
  if (real?.trails && real.trails.length > 0) {
    // Cap: prefer strongest (highest strength) trails.
    let trails = [...real.trails].sort((a, b) => b.strength - a.strength);
    if (trails.length > MAX_REAL_NODES) trails = trails.slice(0, MAX_REAL_NODES);

    const nodes: LatticeNode[] = [];
    const posBySkill = new Map<number, THREE.Vector3>();
    for (const t of trails) {
      const hi = strHash(t.goal_pattern) % HUBS.length;
      const hub = HUBS[hi];
      const rng = createSeededRandom(strHash(String(t.skill_id)));
      const dir = randomUnit(rng);
      const r = LOBE_RADIUS * Math.cbrt(rng());
      const pos = hub.pos.clone().addScaledVector(dir, r);
      clampInward(pos);
      posBySkill.set(t.skill_id, pos);
      nodes.push({
        pos,
        color: new THREE.Color(hub.color),
        radius: SAT_RADIUS * (0.6 + THREE.MathUtils.clamp(t.strength, 0, 1) * 0.8),
        hub: hi,
        isHub: false,
        igniteDelay: THREE.MathUtils.clamp(1 - t.freshness, 0, 1),
      });
    }

    // Edges: link trails that share the same hub to their 1-2 nearest same-hub peers.
    const edgeRng = createSeededRandom(0x54524c53); // "TRLS"
    const edges: LatticeEdge[] = [];
    const seen = new Set<string>();
    for (let i = 0; i < trails.length; i++) {
      const ti = trails[i];
      const hiI = strHash(ti.goal_pattern) % HUBS.length;
      const posI = posBySkill.get(ti.skill_id)!;
      // Find up to 2 nearest same-hub peers.
      const peers = trails
        .map((tj, j) => ({
          j,
          hi: strHash(tj.goal_pattern) % HUBS.length,
          d: posI.distanceTo(posBySkill.get(tj.skill_id)!),
        }))
        .filter((x) => x.j !== i && x.hi === hiI)
        .sort((a, b) => a.d - b.d)
        .slice(0, 2);
      for (const { j } of peers) {
        const key = i < j ? `${i}-${j}` : `${j}-${i}`;
        if (seen.has(key)) continue;
        seen.add(key);
        const posJ = posBySkill.get(trails[j].skill_id)!;
        const color = new THREE.Color(HUBS[hiI].color).multiplyScalar(0.8);
        edges.push({ a: posI, b: posJ, color, phase: edgeRng() * TAU, speed: 0.4 + edgeRng() });
      }
    }
    return { nodes, edges };
  }

  /* ================================================================
   * BRANCH C — synthetic fallback (original implementation, unchanged)
   * ============================================================== */

  /* ---- nodes: 1 hub per anchor + tier-budgeted satellites per lobe ---- */
  const nodes: LatticeNode[] = [];
  HUBS.forEach((hub, hi) => {
    const pos = hub.pos.clone();
    nodes.push({
      pos,
      color: new THREE.Color(hub.color),
      radius: HUB_RADIUS,
      hub: hi,
      isHub: true,
      igniteDelay: igniteDelayFor(pos),
    });
  });
  const satN = SATELLITES_PER_HUB[tier];
  HUBS.forEach((hub, hi) => {
    const base = new THREE.Color(hub.color);
    for (let s = 0; s < satN; s++) {
      // Uniform-in-sphere scatter (cbrt for even volume density).
      const dir = randomUnit(random);
      const r = LOBE_RADIUS * Math.cbrt(random());
      const p = hub.pos.clone().addScaledVector(dir, r);
      clampInward(p);
      // Slight per-node value variation gives the cluster depth.
      const c = base.clone().multiplyScalar(0.7 + random() * 0.5);
      nodes.push({
        pos: p,
        color: c,
        radius: SAT_RADIUS * (0.8 + random() * 0.5),
        hub: hi,
        isHub: false,
        igniteDelay: igniteDelayFor(p),
      });
    }
  });

  /* ---- edges: hub→satellite spokes + k-nearest INTRA-cluster links ---- */
  const edges: LatticeEdge[] = [];
  const k = EDGE_K[tier];
  HUBS.forEach((hub, hi) => {
    const hubNode = nodes.find((n) => n.hub === hi && n.isHub)!;
    const cluster = nodes.filter((n) => n.hub === hi && !n.isHub);
    const hubColor = new THREE.Color(hub.color);
    const pushEdge = (a: THREE.Vector3, b: THREE.Vector3, color: THREE.Color) =>
      edges.push({ a, b, color, phase: random() * TAU, speed: 0.5 + random() * 1.5 });

    // Spokes: every satellite links to its hub.
    cluster.forEach((sat) => pushEdge(hubNode.pos, sat.pos, hubColor));

    // k-nearest links within the cluster (deduped, intra-region only).
    if (k > 0) {
      const seen = new Set<string>();
      cluster.forEach((sat, si) => {
        const near = cluster
          .map((o, oi) => ({ oi, d: sat.pos.distanceTo(o.pos) }))
          .filter((x) => x.oi !== si)
          .sort((a, b) => a.d - b.d)
          .slice(0, k);
        near.forEach(({ oi }) => {
          const key = si < oi ? `${si}-${oi}` : `${oi}-${si}`;
          if (seen.has(key)) return;
          seen.add(key);
          pushEdge(sat.pos, cluster[oi].pos, hubColor.clone().multiplyScalar(0.85));
        });
      });
    }
  });

  return { nodes, edges };
}

/* ---------------------------------------------------------------------------
 * Shaders. The edge + backbone fragment is a VERBATIM copy of NervousSystem's
 * WIRE_FRAGMENT (plus the reduced-motion + arrival deltas required by THE LAW)
 * — a lattice packet and a nervous-bus packet MUST be the same visual language
 * (internal circuit + external spinal bundle = one nervous infrastructure).
 * KEEP IN SYNC if NervousSystem.tsx's WIRE_FRAGMENT changes. (Copied, not
 * imported, to avoid touching the frozen nerve component.)
 * ------------------------------------------------------------------------- */

// Edge + backbone vertex (TubeGeometry): the built-in uv.x runs along the tube, so it
// is the travel coordinate directly (same as NervousSystem's WIRE_VERTEX).
const BACKBONE_VERTEX = /* glsl */ `
  attribute vec3 aWireColor;
  attribute float aPhase;
  attribute float aSpeed;

  varying vec2 vUv;
  varying vec3 vColor;
  varying float vPhase;
  varying float vSpeed;

  void main() {
    vUv = uv;
    vColor = aWireColor;
    vPhase = aPhase;
    vSpeed = aSpeed;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

// Adapted from NervousSystem.tsx WIRE_FRAGMENT (same packet visual language).
// NervousSystem additionally multiplies flowTime by a directional uFlowDir
// (data-true I/O: knowledge up / directives down); the lattice keeps its flow
// one-directional, so this copy intentionally omits uFlowDir. Keep the packet
// math in sync if NervousSystem's changes.
//
// LAW deltas vs. the lab/NervousSystem copy:
//  • uReducedMotion freezes packet travel (settles to a static dim/bright
//    dither — the graph stays LIT and WIRED, it just stops flowing).
//  • uArrival wipes each cable in along its own length (edges snap into place
//    only after the nodes they join have ignited).
const WIRE_FRAGMENT = /* glsl */ `
  uniform float uTime;
  uniform float uBurst;
  uniform float uHold;
  uniform float uSignalGain;
  uniform float uCarrierGain; // lifts the dim wire so the GRAPH reads even between packets
  uniform float uArrival;       // 0 settled .. 1 arriving (coalescence wipe)
  uniform float uReducedMotion; // 1 = no packet travel (a11y)

  varying vec2 vUv;
  varying vec3 vColor;
  varying float vPhase;
  varying float vSpeed;

  void main() {
    // FIBER-OPTIC identity: a near-black whispered carrier (the cable body) with
    // bright packets racing on top. uCarrierGain lifts the carrier just enough
    // that the connection itself is faintly ALWAYS visible — so the lattice
    // reads as a WIRED graph, not isolated dots.
    vec3 carrier = vColor * 0.08 * uCarrierGain;

    // Discrete light-bead (packet) racing root→tip. Flow time is gated by
    // (1.0 - uHold) AND (1.0 - uReducedMotion): when either is 1 the fract
    // freezes, packets stop mid-cable — the "waiting on you" hold + the a11y
    // calm both read as a still, lit graph.
    float motion = (1.0 - uHold) * (1.0 - uReducedMotion);
    float flowTime = uTime * vSpeed * motion;
    float flow = fract(vUv.x * 4.0 - flowTime + vPhase);

    // Hard sparse bead — tight window, NO wake term. ~90% of each wire is dark
    // at any frame → mitigates additive stack-up.
    float packet = smoothstep(0.86, 0.90, flow) * smoothstep(0.98, 0.94, flow);

    // Signal color: pure cyan at idle, shifts toward white on real burst. Gain
    // pushes peak luma >> 1.0 so the bead crosses the bloom knee.
    vec3 signal = mix(vec3(0.0, 1.0, 1.0), vec3(1.0), uBurst);
    vec3 finalColor = carrier + signal * packet * uSignalGain;

    // Burst surge: doubles intensity + whitens signal.
    finalColor *= (1.0 + uBurst * 2.5);

    // Hold dim: approval pause freezes packets (time gate above) AND dims the
    // residual carrier to near-zero — the bus goes dark while the mind defers.
    finalColor *= mix(1.0, 0.2, uHold);

    // ── COALESCENCE wipe (additive: uArrival==0 -> canon settled wire) ──
    // The cable draws in along its own length. progress runs 0..1 as arrival
    // sweeps 1 -> 0, but only after a 0.4 lead-in (so a wire appears AFTER the
    // nodes it joins have started igniting): visible front = step(vUv.x, front).
    float front = clamp(((1.0 - uArrival) - 0.4) / 0.6, 0.0, 1.0);
    float wipe = (uArrival <= 0.0) ? 1.0 : step(vUv.x, front);
    finalColor *= wipe;

    // Hard physical cut at the endpoints (no fading into the nodes).
    if (vUv.x < 0.005 || vUv.x > 0.995) discard;

    gl_FragColor = vec4(finalColor, 1.0);
  }
`;

// NODE shader — glowing energy-sphere: dim region-hued core + bright fresnel
// halo. Idle stays BELOW the bloom knee (uNodeGain lever); the scene burst
// lifts every node past it (per-node firing is live below). instanceColor +
// instanceMatrix are injected by three's instancing prefix on InstancedMesh.
const NODE_VERTEX = /* glsl */ `
  attribute float aActivation;
  attribute float aIgniteDelay;

  varying vec3 vColor;
  varying vec3 vNormalV;
  varying vec3 vViewDirV;
  varying float vActivation;
  varying float vIgniteDelay;

  void main() {
    #ifdef USE_INSTANCING_COLOR
      vColor = instanceColor;
    #else
      vColor = vec3(0.0, 1.0, 1.0);
    #endif
    vActivation = aActivation;
    vIgniteDelay = aIgniteDelay;
    vec4 mvPosition = modelViewMatrix * instanceMatrix * vec4(position, 1.0);
    vNormalV = normalize(normalMatrix * mat3(instanceMatrix) * normal);
    vViewDirV = -mvPosition.xyz;
    gl_Position = projectionMatrix * mvPosition;
  }
`;

const NODE_FRAGMENT = /* glsl */ `
  uniform float uBurst;
  uniform float uHold;
  uniform float uNodeGain;
  uniform float uArrival; // 0 settled .. 1 arriving (coalescence ignite)

  varying vec3 vColor;
  varying vec3 vNormalV;
  varying vec3 vViewDirV;
  varying float vActivation;
  varying float vIgniteDelay;

  void main() {
    vec3 N = normalize(vNormalV);
    vec3 V = normalize(vViewDirV);
    float fres = pow(1.0 - clamp(dot(N, V), 0.0, 1.0), 2.5);

    // Energy sphere: bright region-hued core + brighter fresnel halo (hue
    // UNCHANGED — only luminance is lifted, so the sacred palette holds).
    vec3 core = vColor * 0.72;
    vec3 rim = vColor * fres * 1.7;
    vec3 col = (core + rim) * uNodeGain;

    // P2 — DATA-TRUE per-node firing: when this node's hub ran its kind of real
    // work, surge in the node's own hue (crossing the bloom knee) + whiten the
    // core. This is the lattice "thinking" region-by-region on live events.
    float act = clamp(vActivation, 0.0, 1.0);
    col += vColor * act * 2.2;
    col = mix(col, vec3(1.0), act * 0.5);

    // Whole-organism pulse on directive / synthesis / burst events.
    col = mix(col, vec3(1.0), uBurst * 0.5);
    col *= (1.0 + uBurst * 1.8);

    // Approval hold: defer to amber + dim, mirroring the cortex and the bus.
    vec3 amber = vec3(1.0, 0.62, 0.22);
    col = mix(col, col * amber + amber * 0.04, uHold * 0.85);
    col *= mix(1.0, 0.4, uHold);

    // ── COALESCENCE ignite (additive: uArrival==0 -> fully lit) ──
    // The computer powers on from the ROUTER core outward: each node fades up
    // over a 0.25 window starting at its own normalized distance-from-center,
    // measured against (1.0 - uArrival) so the wave sweeps as arrival -> 0.
    float ignite = (uArrival <= 0.0)
      ? 1.0
      : smoothstep(vIgniteDelay, vIgniteDelay + 0.25, 1.0 - uArrival);
    col *= ignite;
    // A small spark overshoot exactly at the ignition front.
    col += vColor * pow(ignite, 4.0) * (1.0 - ignite) * 3.0;

    gl_FragColor = vec4(col, 1.0);
  }
`;

/** A near-black teal carrier for the backbone (packets are cyan regardless). */
const BACKBONE_TINT = new THREE.Color('#0a3a44');

export default function NodeLattice({
  uniforms,
  tier = 'high',
  reducedMotion = false,
}: {
  uniforms: CognitionUniforms;
  tier?: QualityTier;
  /** a11y: when true, packets freeze and coalescence is assembled (no travel). */
  reducedMotion?: boolean;
}) {
  // One shared lever the frame loop writes; both wire materials + the node
  // material read it. Snapping it (vs. a per-material literal) keeps the three
  // draw calls in lock-step and lets reduced-motion be honored live.
  const reducedMotionUniform = useRef({ value: reducedMotion ? 1 : 0 });
  reducedMotionUniform.current.value = reducedMotion ? 1 : 0;

  // ── REAL-DATA self-fetch ──────────────────────────────────────────────────
  // Mount once: try knowledge-graph, fall back to trails. If both are empty,
  // `real` stays undefined → synthetic fallback in buildLatticeData.
  // Re-fetch on every `telemetry` cognition event (debounced: only one
  // in-flight fetch at a time via the fetchingRef guard).
  const [real, setReal] = useState<RealLatticeData | undefined>(undefined);
  const fetchingRef = useRef(false);

  const doFetch = () => {
    if (fetchingRef.current) return;
    fetchingRef.current = true;
    void (async () => {
      try {
        const [graphEdges, trails] = await Promise.all([
          fetchFactGraph('project', 2),
          Promise.resolve(getKnownTrails() as TrailRow[]),
        ]);
        // Only set real if we have actual data — keeps synthetic alive offline.
        if (graphEdges.length > 0 || trails.length > 0) {
          setReal({ graphEdges, trails });
        }
      } finally {
        fetchingRef.current = false;
      }
    })();
  };

  // Initial fetch on mount.
  useEffect(() => {
    doFetch();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Re-fetch on telemetry events (trails may have grown since mount).
  useEffect(() => {
    return subscribeCognition((event) => {
      if (event.type === 'telemetry') {
        doFetch();
      }
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  // ─────────────────────────────────────────────────────────────────────────

  const built = useMemo(() => {
    const { nodes, edges } = buildLatticeData(tier, real);

    /* ---- 1. NODES → InstancedMesh ---- */
    const nodeGeo = new THREE.IcosahedronGeometry(1, 1); // unit; per-instance scale = radius
    const nodeMat = new THREE.ShaderMaterial({
      vertexShader: NODE_VERTEX,
      fragmentShader: NODE_FRAGMENT,
      uniforms: {
        uBurst: uniforms.uBurst,
        uHold: uniforms.uHold,
        uArrival: uniforms.uArrival,
        uNodeGain: { value: NODE_GAIN }, // idle-brightness lever (keep idle below knee)
      },
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      // depthTest off so the glowing interior reads THROUGH the (now glass)
      // cortex shell — an x-ray of the living circuitry. Tuning point for HIS eyes.
      depthTest: false,
      toneMapped: false,
    });
    const nodeMesh = new THREE.InstancedMesh(nodeGeo, nodeMat, nodes.length);
    const dummy = new THREE.Object3D();
    const colorArray = new Float32Array(nodes.length * 3);
    nodes.forEach((n, i) => {
      dummy.position.copy(n.pos);
      dummy.scale.setScalar(n.radius);
      dummy.updateMatrix();
      nodeMesh.setMatrixAt(i, dummy.matrix);
      colorArray[i * 3] = n.color.r;
      colorArray[i * 3 + 1] = n.color.g;
      colorArray[i * 3 + 2] = n.color.b;
    });
    nodeMesh.instanceColor = new THREE.InstancedBufferAttribute(colorArray, 3);
    nodeMesh.instanceMatrix.needsUpdate = true;
    nodeMesh.frustumCulled = false;
    nodeMesh.renderOrder = 4;

    // P2 — per-node firing: a 0..1 activation per instance, bumped when this
    // node's hub runs its kind of real work, decayed each frame. Dynamic
    // instanced attribute the node shader reads as aActivation.
    const activationArr = new Float32Array(nodes.length);
    const activationAttr = new THREE.InstancedBufferAttribute(activationArr, 1);
    activationAttr.setUsage(THREE.DynamicDrawUsage);
    nodeGeo.setAttribute('aActivation', activationAttr);

    // COALESCENCE: static per-instance ignite delay (router→out). Baked once.
    const igniteArr = new Float32Array(nodes.map((n) => n.igniteDelay));
    nodeGeo.setAttribute('aIgniteDelay', new THREE.InstancedBufferAttribute(igniteArr, 1));

    const hubOfInstance = new Int8Array(nodes.map((n) => n.hub));

    /* ---- 2. EDGES → merged thin tubes (legible "wired graph") ---- */
    // 1px LineSegments were near-invisible (esp. additive over a busy scene);
    // thin tubes read as actual connections. Same WIRE shader + tube-uv vertex
    // as the backbone, so packets travel identically. One merged draw call.
    const edgeTubes: THREE.BufferGeometry[] = [];
    edges.forEach((e) => {
      const g = new THREE.TubeGeometry(new THREE.LineCurve3(e.a.clone(), e.b.clone()), 1, EDGE_TUBE_RADIUS, 5, false);
      const vc = g.attributes.position.count;
      const cArr = new Float32Array(vc * 3);
      const pArr = new Float32Array(vc);
      const sArr = new Float32Array(vc);
      for (let i = 0; i < vc; i++) {
        cArr[i * 3] = e.color.r;
        cArr[i * 3 + 1] = e.color.g;
        cArr[i * 3 + 2] = e.color.b;
        pArr[i] = e.phase;
        sArr[i] = e.speed;
      }
      g.setAttribute('aWireColor', new THREE.BufferAttribute(cArr, 3));
      g.setAttribute('aPhase', new THREE.BufferAttribute(pArr, 1));
      g.setAttribute('aSpeed', new THREE.BufferAttribute(sArr, 1));
      edgeTubes.push(g);
    });
    const edgeGeo = mergeGeometries(edgeTubes);
    edgeTubes.forEach((g) => g.dispose());
    const edgeMat = new THREE.ShaderMaterial({
      vertexShader: BACKBONE_VERTEX,
      fragmentShader: WIRE_FRAGMENT,
      uniforms: {
        uTime: uniforms.uTime,
        uBurst: uniforms.uBurst,
        uHold: uniforms.uHold,
        uArrival: uniforms.uArrival,
        uReducedMotion: reducedMotionUniform.current,
        uSignalGain: { value: SIGNAL_GAIN },
        uCarrierGain: { value: EDGE_CARRIER_GAIN }, // wires always-visible = the graph reads (dial down if too web-like)
      },
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      depthTest: false,
    });
    const edgeMesh = new THREE.Mesh(edgeGeo, edgeMat);
    edgeMesh.frustumCulled = false;
    edgeMesh.renderOrder = 4;

    /* ---- 3. BACKBONE → merged tubes (center ROUTER → each anatomical hub) ---- */
    const bbRandom = createSeededRandom(0x4242424e); // "BBBN" — own deterministic stream
    const router = HUBS[HUBS.length - 1];
    const tubeGeoms: THREE.BufferGeometry[] = [];
    for (let i = 0; i < HUBS.length - 1; i++) {
      const hub = HUBS[i];
      const mid = new THREE.Vector3().lerpVectors(router.pos, hub.pos, 0.5);
      // Slight bow so the four buses don't read as flat spokes.
      mid.addScaledVector(randomUnit(bbRandom), 0.03);
      const curve = new THREE.CatmullRomCurve3([router.pos.clone(), mid, hub.pos.clone()]);
      const g = new THREE.TubeGeometry(curve, 32, BACKBONE_TUBE_RADIUS, 6, false);
      const vc = g.attributes.position.count;
      const cArr = new Float32Array(vc * 3);
      const pArr = new Float32Array(vc);
      const sArr = new Float32Array(vc);
      const phase = bbRandom() * TAU;
      const speed = 0.4 + bbRandom() * 0.8; // backbone pulses slower (major bus)
      for (let v = 0; v < vc; v++) {
        cArr[v * 3] = BACKBONE_TINT.r;
        cArr[v * 3 + 1] = BACKBONE_TINT.g;
        cArr[v * 3 + 2] = BACKBONE_TINT.b;
        pArr[v] = phase;
        sArr[v] = speed;
      }
      g.setAttribute('aWireColor', new THREE.BufferAttribute(cArr, 3));
      g.setAttribute('aPhase', new THREE.BufferAttribute(pArr, 1));
      g.setAttribute('aSpeed', new THREE.BufferAttribute(sArr, 1));
      tubeGeoms.push(g);
    }
    const backboneGeo = mergeGeometries(tubeGeoms);
    tubeGeoms.forEach((g) => g.dispose());
    const backboneMat = new THREE.ShaderMaterial({
      vertexShader: BACKBONE_VERTEX,
      fragmentShader: WIRE_FRAGMENT,
      uniforms: {
        uTime: uniforms.uTime,
        uBurst: uniforms.uBurst,
        uHold: uniforms.uHold,
        uArrival: uniforms.uArrival,
        uReducedMotion: reducedMotionUniform.current,
        uSignalGain: { value: SIGNAL_GAIN },
        uCarrierGain: { value: BACKBONE_CARRIER_GAIN }, // the major bus: wire slightly brighter than the edges
      },
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      depthTest: false,
    });
    const backboneMesh = new THREE.Mesh(backboneGeo, backboneMat);
    backboneMesh.frustumCulled = false;
    backboneMesh.renderOrder = 4;

    return {
      nodeMesh, nodeGeo, nodeMat, edgeMesh, edgeGeo, edgeMat, backboneMesh, backboneGeo, backboneMat,
      activationArr, activationAttr, hubOfInstance,
    };
  }, [uniforms, tier, real]);

  // P2 — live firing: bump the activation of the hub a real cognition event maps
  // to (DATA-TRUE; same tool->lobe routing the cortex uses), then decay it each
  // frame. The lattice stays a pure SUBSCRIBER. useFrame is a no-op while idle.
  const firingRef = useRef(false);
  useEffect(() => {
    const { activationArr, hubOfInstance } = built;
    return subscribeCognition((event) => {
      const target = hubIndexForEvent(event);
      if (target === null) return;
      const amount = target === -1 ? 0.6 : 1.0;
      for (let i = 0; i < activationArr.length; i++) {
        if ((target === -1 || hubOfInstance[i] === target) && activationArr[i] < amount) {
          activationArr[i] = amount;
        }
      }
      firingRef.current = true;
    });
  }, [built]);

  // Dev-only live tuning dial — mirrors window.__POINTFIELD for the point-field.
  // Tune the lattice vividness live in the operator's real-GPU browser, then
  // report values to bake as the new TUNABLES defaults. Friendly keys map onto
  // the three materials' brightness uniforms:
  //   window.__NODELATTICE.nodeGain        = 1.6   // node sphere brightness (NODE_GAIN)
  //   window.__NODELATTICE.edgeCarrier     = 5     // lobe-wire always-on glow (EDGE_CARRIER_GAIN)
  //   window.__NODELATTICE.backboneCarrier = 5.5   // major-bus wire glow (BACKBONE_CARRIER_GAIN)
  //   window.__NODELATTICE.signalGain      = 4     // travelling-packet peak luma (SIGNAL_GAIN)
  // Skipped in production. Honest caveat: pushing brightness too far re-invites
  // the additive white-haze the crisp pass just killed — dial up gently.
  useEffect(() => {
    if (typeof window === 'undefined' || process.env.NODE_ENV === 'production') return;
    const { nodeMat, edgeMat, backboneMat } = built;
    const dial: Record<string, { get: () => number; set: (v: number) => void }> = {
      nodeGain: {
        get: () => nodeMat.uniforms.uNodeGain.value,
        set: (v) => { nodeMat.uniforms.uNodeGain.value = v; },
      },
      edgeCarrier: {
        get: () => edgeMat.uniforms.uCarrierGain.value,
        set: (v) => { edgeMat.uniforms.uCarrierGain.value = v; },
      },
      backboneCarrier: {
        get: () => backboneMat.uniforms.uCarrierGain.value,
        set: (v) => { backboneMat.uniforms.uCarrierGain.value = v; },
      },
      signalGain: {
        // both wire materials share one SIGNAL_GAIN — keep the dial in lock-step.
        get: () => edgeMat.uniforms.uSignalGain.value,
        set: (v) => {
          edgeMat.uniforms.uSignalGain.value = v;
          backboneMat.uniforms.uSignalGain.value = v;
        },
      },
    };
    const w = window as unknown as { __NODELATTICE?: unknown };
    w.__NODELATTICE = new Proxy(
      {},
      {
        get: (_t, key: string) => dial[key]?.get(),
        set: (_t, key: string, value: number) => {
          dial[key]?.set(value);
          return true;
        },
        ownKeys: () => Object.keys(dial),
        getOwnPropertyDescriptor: () => ({ enumerable: true, configurable: true }),
      },
    );
    return () => {
      delete w.__NODELATTICE;
    };
  }, [built]);

  useFrame(() => {
    if (!firingRef.current) return;
    const { activationArr, activationAttr } = built;
    let maxAct = 0;
    for (let i = 0; i < activationArr.length; i++) {
      const a = activationArr[i] * 0.93; // ~0.5s firing pulse
      activationArr[i] = a;
      if (a > maxAct) maxAct = a;
    }
    if (maxAct < 0.003) {
      activationArr.fill(0);
      firingRef.current = false;
    }
    activationAttr.needsUpdate = true;
  });

  useEffect(() => {
    return () => {
      built.nodeGeo.dispose();
      built.nodeMat.dispose();
      built.edgeGeo.dispose();
      built.edgeMat.dispose();
      built.backboneGeo.dispose();
      built.backboneMat.dispose();
    };
  }, [built]);

  return (
    <group>
      <primitive object={built.nodeMesh} />
      <primitive object={built.edgeMesh} />
      <primitive object={built.backboneMesh} />
    </group>
  );
}

